function adminCustomerDriverDetailsEmailReviewFallbackItem(): AdminCustomerDriverDetailsEmailReviewItem {
  return {
    actionLabel: "Review email to customer",
    adminReviewRequired: true,
    customerEmailReady: false,
    disabled_send_status: "blocked",
    external_send: false,
    item_key: "customer_driver_details_email",
    label: "Customer driver details ready",
    readiness_status: "blocked",
    sendingEnabled: false,
    status: "setup_only",
  };
}

function adminEmailActivationPreflightFallbackState(
  message = "Email activation preflight is setup-only.",
): AdminEmailActivationPreflightReadState {
  return {
    activationReady: false,
    blockers: ["provider", "env", "approval", "live_sending"],
    external_send: false,
    liveSendingEnabled: false,
    loadedReference: "",
    message,
    providerConfigured: false,
    providerSelected: false,
    selectedProvider: null,
    sendingEnabled: false,
    status: "idle",
  };
}

function adminCustomerDriverDetailsDisabledSendFallbackState(
  message = "Disabled send is setup-only.",
): AdminCustomerDriverDetailsDisabledSendActionState {
  return {
    actionStatus: "idle",
    external_send: false,
    loadedReference: "",
    message,
    reason: "setup_only_disabled",
    sendingEnabled: false,
    status: "blocked",
  };
}

function adminCustomerDriverDetailsEmailDisabledSendFallbackState(
  message = "Email send uses the gated driver-details email route.",
): AdminCustomerDriverDetailsEmailDisabledSendActionState {
  return {
    ...adminCustomerDriverDetailsDisabledSendFallbackState(message),
    reason: "email_send_gate_closed",
  };
}

function adminCustomerDriverDetailsCustomerInAppFallbackState(
  message = "Load a saved booking with customer copy ready before sending Customer In-App.",
): AdminCustomerDriverDetailsCustomerInAppActionState {
  return {
    actionStatus: "idle",
    deliverySurface: "customer_app",
    external_send: false,
    loadedReference: "",
    message,
    noProviderSend: true,
    notificationStatus: "blocked",
    notificationType: "trip_update",
  };
}

function adminCustomerDriverDetailsDriverInAppFallbackState(
  message = "Load a saved booking with an active driver job link before sending Driver In-App.",
): AdminCustomerDriverDetailsDriverInAppActionState {
  return {
    actionStatus: "idle",
    deliverySurface: "driver_app",
    external_send: false,
    loadedReference: "",
    message,
    noProviderSend: true,
    notificationStatus: "blocked",
    notificationType: "trip_update",
  };
}

function adminCustomerDriverDetailsDisabledSendStatusText(
  state: AdminCustomerDriverDetailsDisabledSendActionState,
  idleText = "Setup-only / send disabled",
) {
  if (state.actionStatus !== "loaded" && state.actionStatus !== "error") {
    return idleText;
  }

  const statusLabel =
    clean(state.status).toLowerCase() === "blocked"
      ? "Blocked"
      : clean(state.status) || "Blocked";

  return `${statusLabel}/no-op, sendingEnabled ${
    state.sendingEnabled ? "true" : "false"
  }, external_send ${state.external_send ? "true" : "false"}`;
}

