function getAssignedDriverSummary(
  bookingRecord: BookingRecord,
  operationalCard?: LoadBookingsOperationalDisplayCard,
) {
  return {
    contact:
      operationalCard?.assigned_driver_phone ||
      clean(bookingRecord.driver_contact),
    name:
      operationalCard?.assigned_driver_display_name ||
      clean(bookingRecord.driver_name) ||
      "—",
    plate:
      operationalCard?.assigned_driver_plate ||
      clean(bookingRecord.driver_plate_number),
    vehicle:
      operationalCard?.assigned_driver_vehicle_type ||
      operationalCard?.vehicle_display ||
      clean(bookingRecord.vehicle),
  };
}

function AssignedDriverSummaryBlock({
  bookingRecord,
  flush = false,
  operationalCard,
}: {
  bookingRecord: BookingRecord;
  flush?: boolean;
  operationalCard?: LoadBookingsOperationalDisplayCard;
}) {
  const driverSummary = getAssignedDriverSummary(bookingRecord, operationalCard);

  return (
    <div
      className={`${flush ? "" : "mt-2 "}rounded-md border border-sky-100 bg-sky-50/70 px-2 py-1.5 text-xs leading-5 text-slate-700`}
      data-assigned-driver-summary={String(bookingRecord.id)}
    >
      <p className="font-semibold text-sky-950">Driver: {driverSummary.name}</p>
      <p className="mt-0.5 truncate text-slate-600">
        {[driverSummary.contact, driverSummary.vehicle, driverSummary.plate].filter(Boolean).join(" | ") ||
          "No assigned driver details"}
      </p>
    </div>
  );
}

function DispatcherStatusSummaryBlock({
  bookingRecord,
  flush = false,
  operationalCard,
}: {
  bookingRecord: BookingRecord;
  flush?: boolean;
  operationalCard?: LoadBookingsOperationalDisplayCard;
}) {
  const status = operationalCard?.booking_status || bookingRecord.status;

  return (
    <div
      className={`${flush ? "" : "mt-2 "}rounded-md border border-emerald-100 bg-emerald-50/70 px-2 py-1.5 text-xs leading-5 text-slate-700`}
      data-dispatcher-status-summary={String(bookingRecord.id)}
    >
      <p className="font-semibold text-emerald-950">Status: {bookingStatusLabel(status)}</p>
    </div>
  );
}

function getOperationalReadinessSummary(
  bookingRecord: BookingRecord,
  operationalCard?: LoadBookingsOperationalDisplayCard,
) {
  const normalizedStatus = clean(operationalCard?.booking_status || bookingRecord.status).toLowerCase();
  const hasDriver = Boolean(
    operationalCard?.assigned_driver_display_name ||
      operationalCard?.assigned_driver_phone ||
      operationalCard?.assigned_driver_plate ||
      hasBookingDriver(bookingRecord),
  );

  const otsProof =
    normalizedStatus === "completed"
      ? "Expected before completion"
      : normalizedStatus === "pob"
        ? "Expected before POB"
        : normalizedStatus === "driver_otw"
          ? "Needed when driver reaches OTS"
          : "Pending OTS step";
  const exceptionReplacement =
    normalizedStatus === "cancelled"
      ? "Review replacement needed"
      : hasDriver
        ? "No replacement recorded"
        : "Driver TBC";

  return {
    exceptionReplacement,
    otsProof,
  };
}

function OperationalReadinessSummaryBlock({
  bookingRecord,
  flush = false,
  operationalCard,
}: {
  bookingRecord: BookingRecord;
  flush?: boolean;
  operationalCard?: LoadBookingsOperationalDisplayCard;
}) {
  const readinessSummary = getOperationalReadinessSummary(bookingRecord, operationalCard);

  return (
    <div
      className={`${flush ? "" : "mt-2 "}rounded-md border border-amber-100 bg-amber-50/70 px-2 py-1.5 text-xs leading-5 text-slate-700`}
      data-operational-readiness-summary={String(bookingRecord.id)}
    >
      <p className="font-semibold text-amber-950">Ops: {readinessSummary.otsProof}</p>
      <p className="mt-0.5 truncate text-slate-600">
        Replacement: {readinessSummary.exceptionReplacement}
      </p>
    </div>
  );
}

