function clean(value: string | number | null | undefined) {
  return (value ?? "").toString().trim();
}

function cleanReferenceText(value: string | number | null | undefined) {
  const cleaned = clean(value);

  return /^(?:undefined|null)$/i.test(cleaned) ? "" : cleaned;
}

function compactBookingReference(value: string | number | null | undefined) {
  const reference = cleanReferenceText(value);

  if (reference.length <= 16) {
    return reference || "No ref";
  }

  return `${reference.slice(0, 6)}...${reference.slice(-6)}`;
}

function formatAdminLiveLocationTimestamp(value: string | null | undefined) {
  const cleaned = clean(value);
  const date = new Date(cleaned);

  if (!cleaned || !Number.isFinite(date.getTime())) {
    return "No time";
  }

  return `${date.toLocaleString("en-SG", {
    day: "2-digit",
    hour: "2-digit",
    hour12: false,
    minute: "2-digit",
    month: "short",
    timeZone: "Asia/Singapore",
  })} SGT`;
}

function googleMapsLocationUrl(latitude: number | null | undefined, longitude: number | null | undefined) {
  if (
    typeof latitude !== "number" ||
    typeof longitude !== "number" ||
    !Number.isFinite(latitude) ||
    !Number.isFinite(longitude)
  ) {
    return "";
  }

  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(`${latitude},${longitude}`)}`;
}

type BrowserGoogleMap = {
  fitBounds: (bounds: BrowserGoogleLatLngBounds) => void;
  setCenter: (position: BrowserGoogleLatLngLiteral) => void;
  setZoom: (zoom: number) => void;
};

type BrowserGoogleMarker = {
  setMap: (map: BrowserGoogleMap | null) => void;
};

type BrowserGoogleLatLngLiteral = {
  lat: number;
  lng: number;
};

type AdminActiveJobsBrowserMapMarkerEntry = {
  job: AdminActiveJobsMapLocation;
  position: BrowserGoogleLatLngLiteral;
};

type BrowserGoogleLatLngBounds = {
  extend: (position: BrowserGoogleLatLngLiteral) => void;
};

type BrowserGoogleMapsNamespace = {
  importLibrary?: (libraryName: "maps" | "marker") => Promise<BrowserGoogleMapsNamespace>;
  LatLngBounds?: new () => BrowserGoogleLatLngBounds;
  Map?: new (element: HTMLElement, options: Record<string, unknown>) => BrowserGoogleMap;
  Marker?: new (options: Record<string, unknown>) => BrowserGoogleMarker;
};

const adminActiveJobsBrowserMapScriptLoaders = new Map<
  string,
  Promise<BrowserGoogleMapsNamespace>
>();
const adminActiveJobsBrowserMapCallbackName =
  "__prestigeAdminActiveJobsBrowserMapLoaded";

function readWindowGoogleMaps() {
  const googleRuntime = (window as unknown as {
    google?: {
      maps?: BrowserGoogleMapsNamespace;
    };
  }).google;

  return googleRuntime?.maps || null;
}

async function resolveAdminActiveJobsBrowserGoogleMapsLibraries(
  maps: BrowserGoogleMapsNamespace | null,
) {
  if (!maps) {
    throw new Error("Google Maps JavaScript API did not load safely.");
  }

  if (maps.importLibrary) {
    const mapsLibrary = await maps.importLibrary("maps");
    const markerLibrary = await maps.importLibrary("marker");

    return {
      ...maps,
      ...mapsLibrary,
      LatLngBounds: mapsLibrary.LatLngBounds || maps.LatLngBounds,
      Map: mapsLibrary.Map || maps.Map,
      Marker: markerLibrary.Marker || maps.Marker,
    };
  }

  return maps;
}

function loadAdminActiveJobsBrowserGoogleMaps(apiKey: string) {
  const existingMaps = readWindowGoogleMaps();

  if (
    existingMaps?.importLibrary ||
    (existingMaps?.Map && existingMaps.Marker && existingMaps.LatLngBounds)
  ) {
    return resolveAdminActiveJobsBrowserGoogleMapsLibraries(existingMaps);
  }

  const scriptSource = `https://maps.googleapis.com/maps/api/js?key=${encodeURIComponent(
    apiKey,
  )}&v=weekly&loading=async&callback=${adminActiveJobsBrowserMapCallbackName}`;
  const existingLoader = adminActiveJobsBrowserMapScriptLoaders.get(scriptSource);

  if (existingLoader) {
    return existingLoader;
  }

  const loader = new Promise<BrowserGoogleMapsNamespace>((resolve, reject) => {
    let settled = false;
    let callbackTimeout: number | null = null;
    const fail = (message: string) => {
      if (settled) {
        return;
      }

      settled = true;
      if (callbackTimeout !== null) {
        window.clearTimeout(callbackTimeout);
      }
      reject(new Error(message));
    };
    callbackTimeout = window.setTimeout(() => {
      fail("Google Maps JavaScript API did not load safely.");
    }, 12000);
    const finish = () => {
      if (settled) {
        return;
      }

      const maps = readWindowGoogleMaps();

      void resolveAdminActiveJobsBrowserGoogleMapsLibraries(maps)
        .then((resolvedMaps) => {
          if (resolvedMaps.Map && resolvedMaps.Marker && resolvedMaps.LatLngBounds) {
            settled = true;
            if (callbackTimeout !== null) {
              window.clearTimeout(callbackTimeout);
            }
            resolve(resolvedMaps);
            return;
          }

          fail("Google Maps JavaScript API did not load safely.");
        })
        .catch(() => fail("Google Maps JavaScript API did not load safely."));
    };
    const browserWindow = window as typeof window & {
      [adminActiveJobsBrowserMapCallbackName]?: () => void;
    };
    const existingScript = document.querySelector<HTMLScriptElement>(
      'script[data-admin-active-jobs-browser-map-loader="true"]',
    );

    browserWindow[adminActiveJobsBrowserMapCallbackName] = finish;

    if (existingScript) {
      existingScript.addEventListener(
        "error",
        () => fail("Google Maps JavaScript API failed to load."),
        { once: true },
      );
      return;
    }

    const script = document.createElement("script");
    script.async = true;
    script.dataset.adminActiveJobsBrowserMapLoader = "true";
    script.defer = true;
    script.src = scriptSource;
    script.addEventListener(
      "error",
      () => fail("Google Maps JavaScript API failed to load."),
      { once: true },
    );
    document.head.appendChild(script);
  });

  adminActiveJobsBrowserMapScriptLoaders.set(scriptSource, loader);

  return loader;
}

function adminActiveJobsBrowserMapDomRendered(mapElement: HTMLElement) {
  return Boolean(
    mapElement.querySelector(".gm-style") ||
      mapElement.querySelector('img[src*="StaticMapService.GetMapImage"]'),
  );
}

function adminActiveJobsBrowserMapHasLayout(mapElement: HTMLElement) {
  const rect = mapElement.getBoundingClientRect();

  return (
    rect.width >= 1 &&
    rect.height >= 1 &&
    rect.bottom > 0 &&
    rect.right > 0 &&
    rect.left < window.innerWidth &&
    rect.top < window.innerHeight
  );
}

function waitForAdminActiveJobsBrowserMapLayout(mapElement: HTMLElement) {
  if (adminActiveJobsBrowserMapHasLayout(mapElement)) {
    return Promise.resolve();
  }

  return new Promise<void>((resolve, reject) => {
    const startedAt = Date.now();
    const check = () => {
      if (adminActiveJobsBrowserMapHasLayout(mapElement)) {
        resolve();
        return;
      }

      if (Date.now() - startedAt > 15000) {
        reject(new Error("Google Maps container did not receive layout safely."));
        return;
      }

      window.requestAnimationFrame(check);
    };

    window.requestAnimationFrame(check);
  });
}

function waitForAdminActiveJobsBrowserMapDom(mapElement: HTMLElement) {
  if (adminActiveJobsBrowserMapDomRendered(mapElement)) {
    return Promise.resolve();
  }

  return new Promise<void>((resolve, reject) => {
    let observer: MutationObserver | null = null;
    const timeout = window.setTimeout(() => {
      observer?.disconnect();
      reject(new Error("Google Maps visual DOM did not render safely."));
    }, 15000);
    observer = new MutationObserver(() => {
      if (!adminActiveJobsBrowserMapDomRendered(mapElement)) {
        return;
      }

      window.clearTimeout(timeout);
      observer?.disconnect();
      resolve();
    });

    observer.observe(mapElement, {
      childList: true,
      subtree: true,
    });
  });
}

function adminActiveJobsBrowserMapTileX(longitude: number, zoom: number) {
  return Math.floor(((longitude + 180) / 360) * 2 ** zoom);
}

function adminActiveJobsBrowserMapTileY(latitude: number, zoom: number) {
  const latitudeRadians = (latitude * Math.PI) / 180;

  return Math.floor(
    ((1 - Math.log(Math.tan(latitudeRadians) + 1 / Math.cos(latitudeRadians)) / Math.PI) / 2) *
      2 ** zoom,
  );
}

function renderAdminActiveJobsBrowserMapTileFallback(
  mapElement: HTMLElement,
  position: BrowserGoogleLatLngLiteral,
) {
  const zoom = 15;
  const centerTileX = adminActiveJobsBrowserMapTileX(position.lng, zoom);
  const centerTileY = adminActiveJobsBrowserMapTileY(position.lat, zoom);
  const tileSize = 256;

  mapElement.innerHTML = "";
  mapElement.setAttribute("data-admin-active-jobs-map-google-tile-base", "true");

  for (let tileXOffset = -3; tileXOffset <= 3; tileXOffset += 1) {
    for (let tileYOffset = -2; tileYOffset <= 2; tileYOffset += 1) {
      const tileImage = document.createElement("img");
      tileImage.alt = "";
      tileImage.decoding = "async";
      tileImage.loading = "eager";
      tileImage.setAttribute("data-admin-active-jobs-map-google-tile", "true");
      tileImage.src = `https://mt.google.com/vt/lyrs=m&x=${centerTileX + tileXOffset}&y=${
        centerTileY + tileYOffset
      }&z=${zoom}`;
      tileImage.style.height = `${tileSize}px`;
      tileImage.style.left = `calc(50% + ${tileXOffset * tileSize - tileSize / 2}px)`;
      tileImage.style.position = "absolute";
      tileImage.style.top = `calc(50% + ${tileYOffset * tileSize - tileSize / 2}px)`;
      tileImage.style.width = `${tileSize}px`;
      mapElement.appendChild(tileImage);
    }
  }

  const attribution = document.createElement("span");
  attribution.setAttribute("data-admin-active-jobs-map-google-tile-attribution", "true");
  attribution.textContent = "Map tiles © Google";
  attribution.style.background = "rgba(255, 255, 255, 0.85)";
  attribution.style.bottom = "2px";
  attribution.style.color = "#111827";
  attribution.style.fontSize = "10px";
  attribution.style.lineHeight = "1";
  attribution.style.padding = "2px 3px";
  attribution.style.position = "absolute";
  attribution.style.right = "4px";
  mapElement.appendChild(attribution);
}

function waitForAdminActiveJobsBrowserMapTileFallback(mapElement: HTMLElement) {
  const tileImages = [
    ...mapElement.querySelectorAll<HTMLImageElement>('[data-admin-active-jobs-map-google-tile="true"]'),
  ];

  if (tileImages.some((tileImage) => tileImage.complete && tileImage.naturalWidth > 0)) {
    return Promise.resolve();
  }

  return new Promise<void>((resolve, reject) => {
    const timeout = window.setTimeout(() => {
      cleanup();
      reject(new Error("Google map tile fallback did not load safely."));
    }, 10000);
    const check = () => {
      if (!tileImages.some((tileImage) => tileImage.complete && tileImage.naturalWidth > 0)) {
        return;
      }

      window.clearTimeout(timeout);
      cleanup();
      resolve();
    };
    const cleanup = () => {
      tileImages.forEach((tileImage) => {
        tileImage.removeEventListener("error", check);
        tileImage.removeEventListener("load", check);
      });
    };

    tileImages.forEach((tileImage) => {
      tileImage.addEventListener("error", check);
      tileImage.addEventListener("load", check);
    });
  });
}

function validAdminActiveJobMapPosition(job: AdminActiveJobsMapLocation) {
  const latitude = Number(job.latitude);
  const longitude = Number(job.longitude);

  if (
    !Number.isFinite(latitude) ||
    latitude < -90 ||
    latitude > 90 ||
    !Number.isFinite(longitude) ||
    longitude < -180 ||
    longitude > 180
  ) {
    return null;
  }

  return {
    lat: latitude,
    lng: longitude,
  };
}

function projectAdminActiveJobsBrowserMapPosition(position: BrowserGoogleLatLngLiteral) {
  const sinLatitude = Math.max(
    -0.9999,
    Math.min(0.9999, Math.sin((position.lat * Math.PI) / 180)),
  );

  return {
    x: (position.lng + 180) / 360,
    y: 0.5 - Math.log((1 + sinLatitude) / (1 - sinLatitude)) / (4 * Math.PI),
  };
}

function AdminActiveJobsBrowserMap({
  activeJobs,
  apiKey,
  mapId,
}: {
  activeJobs: AdminActiveJobsMapLocation[];
  apiKey: string;
  mapId: string;
}) {
  const mapSlotRef = useRef<HTMLDivElement | null>(null);
  const mapElementRef = useRef<HTMLElement | null>(null);
  const mapRef = useRef<BrowserGoogleMap | null>(null);
  const markersRef = useRef<BrowserGoogleMarker[]>([]);
  const [renderState, setRenderState] = useState<"error" | "loading" | "ready">("loading");
  const activeMarkerJobs = useMemo(
    () =>
      activeJobs
        .map((job) => ({
          job,
          position: validAdminActiveJobMapPosition(job),
        }))
        .filter(
          (entry): entry is AdminActiveJobsBrowserMapMarkerEntry =>
            entry.position !== null,
        ),
    [activeJobs],
  );
  const overlayMarkers = useMemo(() => {
    if (activeMarkerJobs.length === 0) {
      return [];
    }

    if (activeMarkerJobs.length === 1) {
      const [{ job }] = activeMarkerJobs;
      const reference = compactBookingReference(job.assigned_job_reference || "unknown");

      return [
        {
          key: `${reference}-0`,
          label: `${job.driver_display_label || "Driver"} ${reference}`,
          left: 50,
          reference,
          top: 50,
        },
      ];
    }

    const projected = activeMarkerJobs.map((entry) => ({
      entry,
      point: projectAdminActiveJobsBrowserMapPosition(entry.position),
    }));
    const xValues = projected.map(({ point }) => point.x);
    const yValues = projected.map(({ point }) => point.y);
    const minX = Math.min(...xValues);
    const maxX = Math.max(...xValues);
    const minY = Math.min(...yValues);
    const maxY = Math.max(...yValues);
    const rangeX = Math.max(maxX - minX, 0.000001);
    const rangeY = Math.max(maxY - minY, 0.000001);
    const paddingPercent = 14;

    return projected.map(({ entry, point }, index) => {
      const reference = compactBookingReference(entry.job.assigned_job_reference || "unknown");

      return {
        key: `${reference}-${index}`,
        label: `${entry.job.driver_display_label || "Driver"} ${reference}`,
        left:
          paddingPercent +
          ((point.x - minX) / rangeX) * (100 - paddingPercent * 2),
        reference,
        top:
          paddingPercent +
          ((point.y - minY) / rangeY) * (100 - paddingPercent * 2),
      };
    });
  }, [activeMarkerJobs]);

  useEffect(() => {
    let cancelled = false;
    let tileFallbackInline = false;

    if (!apiKey || activeMarkerJobs.length === 0) {
      return () => {
        cancelled = true;
      };
    }

    const mapElement = document.createElement("div");
    mapElement.setAttribute("data-admin-active-jobs-map-google-base", "true");
    mapElement.style.background = "#e5e7eb";
    mapElement.style.overflow = "hidden";
    mapElement.style.position = "fixed";
    mapElement.style.zIndex = "5";
    document.body.appendChild(mapElement);
    mapElementRef.current = mapElement;

    const updateMapPortalRect = () => {
      const slotElement = mapSlotRef.current;
      const portalElement = mapElementRef.current;

      if (!portalElement) {
        return;
      }

      if (tileFallbackInline) {
        portalElement.style.display = "block";
        portalElement.style.height = "100%";
        portalElement.style.left = "0";
        portalElement.style.position = "absolute";
        portalElement.style.top = "0";
        portalElement.style.width = "100%";
        portalElement.style.zIndex = "0";
        return;
      }

      if (!slotElement) {
        portalElement.style.display = "none";
        return;
      }

      const rect = slotElement.getBoundingClientRect();
      portalElement.style.display =
        rect.width > 0 && rect.height > 0 ? "block" : "none";
      portalElement.style.height = `${Math.max(0, rect.height)}px`;
      portalElement.style.left = `${rect.left}px`;
      portalElement.style.top = `${rect.top}px`;
      portalElement.style.width = `${Math.max(0, rect.width)}px`;
    };
    const resizeObserver =
      typeof ResizeObserver !== "undefined"
        ? new ResizeObserver(updateMapPortalRect)
        : null;

    updateMapPortalRect();
    resizeObserver?.observe(mapSlotRef.current || document.body);
    window.addEventListener("resize", updateMapPortalRect);
    window.addEventListener("scroll", updateMapPortalRect, true);

    void Promise.resolve()
      .then(() => {
        if (!cancelled) {
          setRenderState("loading");
        }

        return loadAdminActiveJobsBrowserGoogleMaps(apiKey);
      })
      .then(async (maps) => {
        if (cancelled || !maps.Map || !maps.Marker || !maps.LatLngBounds) {
          return;
        }

        const MapConstructor = maps.Map;
        const MarkerConstructor = maps.Marker;
        const LatLngBoundsConstructor = maps.LatLngBounds;

        await waitForAdminActiveJobsBrowserMapLayout(mapElement);

        if (cancelled) {
          return;
        }

        if (!mapRef.current) {
          mapRef.current = new MapConstructor(mapElement, {
            center: activeMarkerJobs[0].position,
            clickableIcons: false,
            fullscreenControl: false,
            mapId: mapId || undefined,
            mapTypeControl: false,
            streetViewControl: false,
            zoom: 14,
          });
        }

        markersRef.current.forEach((marker) => marker.setMap(null));
        markersRef.current = [];

        const bounds = new LatLngBoundsConstructor();

        activeMarkerJobs.forEach(({ job, position }) => {
          bounds.extend(position);
          markersRef.current.push(
            new MarkerConstructor({
              map: mapRef.current,
              position,
              title: `${job.driver_display_label || "Driver"} · ${compactBookingReference(
                job.assigned_job_reference || "",
              )}`,
            }),
          );
        });

        if (activeMarkerJobs.length === 1) {
          mapRef.current.setCenter(activeMarkerJobs[0].position);
          mapRef.current.setZoom(15);
        } else {
          mapRef.current.fitBounds(bounds);
        }

        await waitForAdminActiveJobsBrowserMapDom(mapElement);

        if (cancelled) {
          return;
        }

        setRenderState("ready");
      })
      .catch(async () => {
        if (cancelled) {
          return;
        }

        try {
          markersRef.current.forEach((marker) => marker.setMap(null));
          markersRef.current = [];
          mapRef.current = null;
          tileFallbackInline = true;
          mapSlotRef.current?.prepend(mapElement);
          renderAdminActiveJobsBrowserMapTileFallback(mapElement, activeMarkerJobs[0].position);
          updateMapPortalRect();
          await waitForAdminActiveJobsBrowserMapTileFallback(mapElement);

          if (!cancelled) {
            setRenderState("ready");
          }
        } catch {
          if (!cancelled) {
            setRenderState("error");
          }
        }
      });

    return () => {
      cancelled = true;
      resizeObserver?.disconnect();
      window.removeEventListener("resize", updateMapPortalRect);
      window.removeEventListener("scroll", updateMapPortalRect, true);
      markersRef.current.forEach((marker) => marker.setMap(null));
      markersRef.current = [];
      mapRef.current = null;
      mapElementRef.current?.remove();
      mapElementRef.current = null;
      if (mapElement.isConnected) {
        mapElement.remove();
      }
    };
  }, [activeMarkerJobs, apiKey, mapId]);

  return (
    <div
      aria-label="Admin active driver browser map"
      className="mt-1 overflow-hidden rounded border border-lime-200 bg-lime-50"
      data-admin-active-jobs-map-canvas="true"
      data-admin-active-jobs-map-canvas-state={renderState}
    >
      <div
        ref={mapSlotRef}
        className="relative h-48 w-full overflow-hidden bg-transparent sm:h-56"
        data-admin-active-jobs-map-google-slot="true"
      >
        {renderState === "ready"
          ? overlayMarkers.map((marker) => (
              <span
                aria-label={marker.label}
                className="pointer-events-none absolute z-10 flex h-5 w-5 -translate-x-1/2 -translate-y-full items-center justify-center rounded-full border-2 border-white bg-red-600 shadow"
                data-admin-active-jobs-map-overlay-marker={marker.reference}
                key={marker.key}
                style={{
                  left: `${marker.left}%`,
                  top: `${marker.top}%`,
                }}
                title={marker.label}
              >
                <span className="h-2 w-2 rounded-full bg-white" />
              </span>
            ))
          : null}
      </div>
      {renderState === "error" ? (
        <p className="border-t border-lime-100 px-1.5 py-1 text-[10px] font-semibold text-red-800 sm:text-[11px]">
          Embedded map could not load. Use Driver Pin.
        </p>
      ) : null}
    </div>
  );
}

function isInactiveDriver(
  driver: Pick<DriverRecord, "availability_status"> | DriverAssignmentDisplayRecord | null | undefined,
) {
  return clean(driver?.availability_status).toLowerCase() === "inactive";
}

function isAssignableDriver(driver: Pick<DriverRecord, "availability_status"> | DriverAssignmentDisplayRecord) {
  return !isInactiveDriver(driver);
}

function hasBookingDriver(bookingRecord: Pick<BookingRecord, "driver_id" | "driver_name">) {
  return Boolean(bookingRecord.driver_id || clean(bookingRecord.driver_name));
}

function undoCompletedStatus(
  bookingRecord: Pick<BookingRecord, "driver_id" | "driver_name">,
): BookingStatusValue {
  return hasBookingDriver(bookingRecord) ? "assigned" : "confirmed";
}

function bookingStatusLabel(status: string | null) {
  const normalizedStatus = clean(status).toLowerCase();

  if (normalizedStatus === "confirmed") {
    return "Confirmed";
  }

  if (normalizedStatus === "assigned") {
    return "Assigned";
  }

  if (normalizedStatus === "driver_otw") {
    return "Driver OTW";
  }

  if (normalizedStatus === "pob") {
    return "POB";
  }

  if (normalizedStatus === "completed") {
    return "Completed";
  }

  if (normalizedStatus === "cancelled") {
    return "Cancelled";
  }

  return clean(status) || "Pending";
}

function isMarkCompletionMessage(message: Message | null | undefined) {
  return Boolean(
    message &&
      (message.text === "Marking booking completed..." ||
        message.text === "Booking marked completed." ||
        message.text.startsWith("Mark completed failed")),
  );
}

function isUndoCompletionMessage(message: Message | null | undefined) {
  return Boolean(
    message &&
      (message.text === "Undoing completion..." ||
        message.text === "Completion undone." ||
        message.text.startsWith("Undo completed failed")),
  );
}

function isDeleteCompletedJobMessage(message: Message | null | undefined) {
  return Boolean(
    message &&
      (message.text === "Delete cancelled." ||
        message.text === "Deleting completed job..." ||
        message.text === "Completed job deleted." ||
        message.text.startsWith("Delete completed job failed")),
  );
}

function getNeedsReviewWarnings(booking: BookingForm) {
  const warnings: string[] = [];
  const paxValue = Number(clean(booking.pax));
  const customerPriceOverride = clean(booking.customerPriceOverride);
  const customerPriceOverrideValue = Number(customerPriceOverride);

  if (clean(booking.pax) && (!Number.isFinite(paxValue) || paxValue < 1)) {
    warnings.push("Pax value is not valid");
  }

  if (
    customerPriceOverride &&
    (!Number.isFinite(customerPriceOverrideValue) || customerPriceOverrideValue < 0)
  ) {
    warnings.push("Quoted price override is not a valid number");
  }

  return warnings;
}

function getDispatchReleaseTripWarnings(booking: BookingForm) {
  const warnings: string[] = [];
  const bookingType = normalizeBookingType(booking.bookingType);
  const paxValue = Number(clean(booking.pax));

  if (!clean(booking.date)) {
    warnings.push("Pickup date missing");
  }

  if (!clean(booking.time)) {
    warnings.push("Pickup time missing");
  }

  if (!clean(booking.pickup)) {
    warnings.push("Pickup missing");
  }

  if (!clean(booking.dropoff)) {
    warnings.push("Drop-off missing");
  }

  if (!clean(booking.bookingType)) {
    warnings.push("Service type missing");
  }

  if (!clean(booking.vehicle)) {
    warnings.push("Vehicle missing");
  }

  if (!clean(booking.pax) || !Number.isFinite(paxValue) || paxValue < 1) {
    warnings.push("Passenger count missing");
  }

  if (!clean(booking.name)) {
    warnings.push("Passenger name missing");
  }

  if (bookingType === "MNG" && !clean(booking.flight)) {
    warnings.push("Arrival flight missing");
  }

  if (normalizeExtraStopCount(booking.extraStopCount) > 0 && !clean(booking.extraStopLocation)) {
    warnings.push("Extra stop location missing");
  }

  if (
    clean(booking.childSeatRequired) === "yes" &&
    normalizeChildSeatCount(booking.childSeatRequired, booking.childSeatCount) < 1
  ) {
    warnings.push("Child seat count missing");
  }

  return warnings;
}

function formatPrivacySafePlace(value: string | null | undefined, fallback: string) {
  const text = clean(value);

  if (!text) {
    return fallback;
  }

  const sanitized = text
    .replace(/(?:^|[,\s])#\s*[a-z0-9]+(?:[-/][a-z0-9]+)?/gi, " ")
    .replace(/\b(?:unit|floor|level|lvl)\s*#?\s*[a-z0-9]+(?:[-/][a-z0-9]+)?/gi, " ")
    .replace(/\b(?:blk|block)\s*\d+[a-z]?\b/gi, " ")
    .replace(/\b(?:postal|singapore)\s*\d{5,6}\b/gi, " ")
    .replace(/\b\d{5,6}\b/g, " ")
    .replace(/\s*,\s*/g, ", ")
    .replace(/\s+/g, " ")
    .replace(/^,+\s*/, "")
    .replace(/^\d+[a-z]?(?:[-/]\d+[a-z]?)?\s+/i, "")
    .replace(/^,+\s*/, "")
    .trim();
  const firstSafeSegment = sanitized
    .split(",")
    .map((part) => clean(part))
    .find(Boolean);

  return firstSafeSegment || fallback;
}

type ItineraryDisplayStop = {
  location: string;
  time: string;
};

function formatItineraryTimeForDispatch(value: string) {
  const compactTime = clean(value).replace(/\s+/g, "").toLowerCase();
  const amPmMatch = compactTime.match(/^(\d{1,2})(?::?(\d{2}))?(am|pm)$/);

  if (amPmMatch) {
    let hour = Number(amPmMatch[1]);
    const minute = amPmMatch[2] || "00";

    if (amPmMatch[3] === "pm" && hour < 12) {
      hour += 12;
    }

    if (amPmMatch[3] === "am" && hour === 12) {
      hour = 0;
    }

    return `${String(hour).padStart(2, "0")}${minute}hrs`;
  }

  return formatPickupTime(compactTime);
}

function formatDriverItineraryLocation(value: string) {
  const sanitized = clean(value)
    .replace(/\s*,?\s*#\s*[a-z0-9]+(?:[-/][a-z0-9]+)?\s*,?\s*/gi, ", ")
    .replace(/\bSingapore\s+\d{5,6}\b/gi, "")
    .replace(/\b\d{5,6}\b/g, "")
    .replace(/\s*,\s*/g, ", ")
    .replace(/(?:,\s*){2,}/g, ", ")
    .replace(/\s+/g, " ")
    .replace(/,\s*$/g, "")
    .replace(/^,\s*/g, "")
    .trim();
  const parts = sanitized
    .split(",")
    .map((part) => clean(part))
    .filter((part) => part && !/^singapore$/i.test(part));

  if (parts.length <= 1) {
    return parts[0] || sanitized;
  }

  if (/^\d+[a-z]?\b/i.test(parts[0]) && /\b(?:square|hotel|office|atrium|sands)\b/i.test(parts[1])) {
    return `${parts[1]}, ${parts[0]}`;
  }

  const namedLandmark =
    parts.find((part, index) => index > 0 && part.includes("@")) ||
    parts.find((part, index) => index > 0 && /\b(?:tower|square|hotel|atrium|sands|bay)\b/i.test(part));

  if (namedLandmark) {
    return `${parts[0]}, ${namedLandmark}`;
  }

  return parts.slice(0, 2).join(", ");
}

function parseItineraryDisplayStops(value: string) {
  const rawStops = clean(value)
    .split(/\s*>\s*/g)
    .map((part) => clean(part))
    .filter(Boolean);

  if (rawStops.length < 2) {
    return [];
  }

  const stops = rawStops
    .map((rawStop): ItineraryDisplayStop => {
      const stopMatch = rawStop.match(/^(.+?)\s+(?:at|by)\s+(\d{1,2}(?::\d{2})?\s*(?:am|pm)|\d{3,4}\s*hrs?)$/i);

      if (!stopMatch?.[1] || !stopMatch[2]) {
        return {
          location: formatDriverItineraryLocation(rawStop),
          time: "",
        };
      }

      return {
        location: formatDriverItineraryLocation(stopMatch[1]),
        time: formatItineraryTimeForDispatch(stopMatch[2]),
      };
    })
    .filter((stop) => clean(stop.location));
  const timedStopCount = stops.filter((stop) => clean(stop.time)).length;

  return timedStopCount >= 2 ? stops : [];
}

function isDspMultiStopItineraryBooking(
  bookingValue: Pick<BookingForm, "bookingType" | "extraStopCount" | "extraStopLocation">,
  itineraryStops = parseItineraryDisplayStops(bookingValue.extraStopLocation),
) {
  return clean(bookingValue.bookingType).toUpperCase() === "DSP" &&
    normalizeExtraStopCount(bookingValue.extraStopCount) >= 2 &&
    itineraryStops.length >= 2;
}

function formatPrivacySafeRoute(
  bookingValue: Pick<BookingForm, "bookingType" | "pickup" | "extraStopCount" | "extraStopLocation" | "dropoff">,
) {
  const pickup = formatPrivacySafePlace(bookingValue.pickup, "Pickup");
  const dropoff = formatPrivacySafePlace(bookingValue.dropoff, "Drop-off");
  const itineraryStops = parseItineraryDisplayStops(bookingValue.extraStopLocation);

  if (isDspMultiStopItineraryBooking(bookingValue, itineraryStops)) {
    return [pickup, "Multi-stop itinerary hidden for privacy", dropoff].filter(Boolean).join(" > ");
  }

  const extraStopParts = clean(bookingValue.extraStopLocation)
    .split(/\s*>\s*/g)
    .map((stop) => formatPrivacySafePlace(stop, "Extra stop"))
    .filter((stop) => stop && stop !== "Extra stop");

  return [pickup, ...extraStopParts, dropoff].filter(Boolean).join(" > ");
}

function bookingTypeIsDeparture(value: string | null | undefined) {
  const cleaned = clean(value).toUpperCase();

  return normalizeBookingType(value) === "DEP" || /\b(?:DEP|DEPARTURE)\b/.test(cleaned);
}

function bookingTypeIsArrival(value: string | null | undefined) {
  const cleaned = clean(value).toUpperCase();

  return /\b(?:MNG|ARR|ARRIVAL|ARRIVING|MEET\s*(?:AND|&)\s*GREET)\b/.test(cleaned);
}

function appendFlightDetailToLocation(location: string, flight: string) {
  if (!location || !flight) {
    return location;
  }

  if (new RegExp(`\\b${flight.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i").test(location)) {
    return location;
  }

  return `${location} (Flight: ${flight})`;
}

function dispatchCopyLocationFlightParts(
  bookingValue: Pick<BookingForm, "bookingType" | "flight" | "pickup" | "dropoff">,
) {
  const flight = clean(bookingValue.flight);
  const pickup = clean(bookingValue.pickup);
  const dropoff = clean(bookingValue.dropoff);
  const flightLine = flight ? `Flight: ${flight}` : "";

  if (!flight) {
    return {
      dropoff,
      pickup,
      standaloneFlightLine: "",
    };
  }

  if (bookingTypeIsDeparture(bookingValue.bookingType)) {
    return {
      dropoff: appendFlightDetailToLocation(dropoff, flight),
      pickup,
      standaloneFlightLine: "",
    };
  }

  if (bookingTypeIsArrival(bookingValue.bookingType)) {
    return {
      dropoff,
      pickup: appendFlightDetailToLocation(pickup, flight),
      standaloneFlightLine: "",
    };
  }

  return {
    dropoff,
    pickup,
    standaloneFlightLine: flightLine,
  };
}

function hasParsedValue(value: unknown) {
  if (Array.isArray(value)) {
    return value.length > 0;
  }

  if (typeof value === "boolean") {
    return value;
  }

  if (typeof value === "string") {
    return clean(value).length > 0;
  }

  return value !== null && value !== undefined;
}

function normaliseEmail(value: string) {
  return clean(value).toLowerCase();
}

function normaliseEmailDomain(value: string | null | undefined) {
  return clean(value).toLowerCase().replace(/^www\./, "");
}

function isPublicEmailDomain(value: string | null | undefined) {
  const domain = normaliseEmailDomain(value);

  return Boolean(domain && publicEmailDomains.has(domain));
}

function isInternalPrestigeEmailDomain(value: string | null | undefined) {
  const domain = normaliseEmailDomain(value);

  return Boolean(domain && internalPrestigeEmailDomains.has(domain));
}

function isIgnoredAccountEmailDomain(value: string | null | undefined) {
  return isPublicEmailDomain(value) || isInternalPrestigeEmailDomain(value);
}

function isInternalPrestigeAccount(value: string | null | undefined) {
  const account = clean(value).toLowerCase().replace(/\s+/g, "");

  return Boolean(account && internalPrestigeAccountTokens.has(account));
}

function getPublicEmailLocalPart(value: string | null | undefined) {
  const email = normaliseEmail(value ?? "");
  const [localPart, domain] = email.split("@");

  return localPart && isPublicEmailDomain(domain) ? localPart : "";
}

function getEmailDomain(value: string) {
  const email = normaliseEmail(value);
  const domain = normaliseEmailDomain(email.split("@")[1]);

  return isIgnoredAccountEmailDomain(domain) ? "" : domain;
}

function normalizeCompanyAccount(value: string | null | undefined, email: string | null | undefined = "") {
  const companyName = clean(value);
  const publicEmailLocalPart = getPublicEmailLocalPart(email);

  if (
    !companyName ||
    isIgnoredAccountEmailDomain(companyName) ||
    isInternalPrestigeAccount(companyName) ||
    (publicEmailLocalPart && companyName.toLowerCase() === publicEmailLocalPart)
  ) {
    return "";
  }

  return companyName;
}

function normalizeBillingIdentityMatch(value: string | number | null | undefined) {
  return clean(value).toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function billingIdentityMatches(first: string | number | null | undefined, second: string | number | null | undefined) {
  const firstKey = normalizeBillingIdentityMatch(first);
  const secondKey = normalizeBillingIdentityMatch(second);

  return Boolean(firstKey && secondKey && firstKey === secondKey);
}

const billingCompanyIdentityIgnoredTokens = new Set([
  "company",
  "co",
  "corp",
  "corporation",
  "gmbh",
  "group",
  "inc",
  "limited",
  "llc",
  "llp",
  "ltd",
  "pte",
  "sdn",
  "sg",
  "singapore",
]);

function normalizeBillingCompanyIdentityMatch(value: string | number | null | undefined) {
  const normalized = normalizeBillingIdentityMatch(billingIdentityBaseAccount(clean(value)));
  const withoutCompanySuffixes = normalized
    .split(" ")
    .filter((token) => token && !billingCompanyIdentityIgnoredTokens.has(token))
    .join(" ")
    .trim();

  return withoutCompanySuffixes || normalized;
}

function billingCompanyIdentityMatches(
  first: string | number | null | undefined,
  second: string | number | null | undefined,
) {
  const firstKey = normalizeBillingCompanyIdentityMatch(first);
  const secondKey = normalizeBillingCompanyIdentityMatch(second);

  return Boolean(firstKey && secondKey && firstKey === secondKey);
}

function formatTravelerBillingAccountLabel(companyAccount: string, travelerName: string) {
  const safeCompany = clean(companyAccount) || "Customer Account";
  const safeTraveler = clean(travelerName) || "Traveler To Confirm";

  return `${safeCompany} [${safeTraveler}]`.slice(0, 220);
}

function billingIdentityBaseAccount(value: string | null | undefined) {
  const account = clean(value);
  const bracketMatch = account.match(/^(.+?)\s+\[[^\]]+\]$/);

  if (bracketMatch?.[1]) {
    return clean(bracketMatch[1]);
  }

  const slashMatch = account.match(/^(.+?)\s+\/\s+.+$/);

  if (slashMatch?.[1]) {
    return clean(slashMatch[1]);
  }

  return account;
}

function saveCrmBillingRecordCustomerAccount(
  record: AdminBookingPersistenceRecord | BookingRecord,
) {
  return clean(record.customer_display_name) || clean((record as BookingRecord).companies?.company_name);
}

function saveCrmBillingRecordTravelerName(
  record: AdminBookingPersistenceRecord | BookingRecord,
) {
  return clean(record.passenger_name) || clean((record as BookingRecord).travelers?.traveler_name);
}

function saveCrmBillingRecordBookerTokens(
  record: AdminBookingPersistenceRecord | BookingRecord,
) {
  return [
    clean(record.contact_display_name) || clean((record as BookingRecord).bookers?.booker_name),
    clean(record.contact_phone) || clean((record as BookingRecord).bookers?.phone),
    clean(record.contact_email) || clean((record as BookingRecord).bookers?.email),
  ].filter(Boolean);
}

function saveCrmCurrentBookerTokens(bookingValue: BookingForm) {
  return [
    clean(bookingValue.booker),
    clean(bookingValue.bookerContact),
    clean(bookingValue.bookerEmail),
  ].filter(Boolean);
}

function saveCrmBillingBookerLabel(bookingValue: BookingForm) {
  return clean(bookingValue.booker) || clean(bookingValue.bookerContact) || clean(bookingValue.bookerEmail) || "";
}

function uniqueBillingTravelerNames(names: string[]) {
  const seen = new Set<string>();
  const unique: string[] = [];

  for (const name of names) {
    const cleaned = clean(name);
    const key = normalizeBillingIdentityMatch(cleaned);

    if (!cleaned || !key || seen.has(key)) {
      continue;
    }

    seen.add(key);
    unique.push(cleaned);
  }

  return unique;
}

function buildSaveCrmBillingIdentityReview(
  bookingValue: BookingForm,
  records: Array<AdminBookingPersistenceRecord | BookingRecord>,
): SaveCrmBillingIdentityReview | null {
  const rawCompanyAccount = normalizeCompanyAccount(bookingValue.company, bookingValue.bookerEmail);
  const bookerLabel = saveCrmBillingBookerLabel(bookingValue);
  const companyAccount = rawCompanyAccount || bookerLabel || clean(bookingValue.name);
  const travelerName = clean(bookingValue.name);
  const currentBookerTokens = saveCrmCurrentBookerTokens(bookingValue);

  if (!companyAccount && currentBookerTokens.length === 0) {
    return null;
  }

  const relatedTravelerNames = records.flatMap((record) => {
    const recordAccount = saveCrmBillingRecordCustomerAccount(record);
    const recordBaseAccount = billingIdentityBaseAccount(recordAccount);
    const companyMatches =
      Boolean(companyAccount) &&
      (billingCompanyIdentityMatches(recordAccount, companyAccount) ||
        billingCompanyIdentityMatches(recordBaseAccount, companyAccount));
    const recordBookerTokens = saveCrmBillingRecordBookerTokens(record);
    const bookerMatches = currentBookerTokens.some((token) =>
      recordBookerTokens.some((recordToken) => billingIdentityMatches(token, recordToken)),
    );

    if (!companyMatches && !bookerMatches) {
      return [];
    }

    const recordTravelerName = saveCrmBillingRecordTravelerName(record);

    return recordTravelerName ? [recordTravelerName] : [];
  });
  const uniqueRelatedTravelerNames = uniqueBillingTravelerNames(relatedTravelerNames);
  const conflictingTravelerNames = travelerName
    ? uniqueRelatedTravelerNames.filter((name) => !billingIdentityMatches(name, travelerName))
    : uniqueRelatedTravelerNames;

  const needsTravelerName = !travelerName;

  if (!needsTravelerName && conflictingTravelerNames.length === 0) {
    return null;
  }

  const accountLabel = formatTravelerBillingAccountLabel(companyAccount, travelerName || "Traveler To Confirm");
  const key = [
    normalizeBillingIdentityMatch(companyAccount),
    normalizeBillingIdentityMatch(bookerLabel),
    normalizeBillingIdentityMatch(travelerName),
    conflictingTravelerNames.map(normalizeBillingIdentityMatch).sort().join("|"),
  ].join("::");

  return {
    accountLabel,
    bookerLabel,
    companyAccount,
    conflictingTravelerNames,
    key,
    matchingRecordCount: uniqueRelatedTravelerNames.length,
    needsTravelerName,
    travelerName,
  };
}

function canonicalServiceTypeForPriceReview(value: string | null | undefined) {
  const rawValue = clean(value);
  const normalizedValue = rawValue.toUpperCase();

  if (!normalizedValue) {
    return "";
  }

  if (/\b(?:DSP|HOURLY|DISPOSAL|STANDBY|WAIT\s+\d+\s*(?:HOURS?|HRS?))\b/.test(normalizedValue)) {
    return "DSP";
  }

  if (/\b(?:DEP|DEPARTURE|DEPART|AIRPORT\s+DROP|DROP\s*OFF\s+(?:AT\s+)?AIRPORT|TO\s+AIRPORT)\b/.test(normalizedValue)) {
    return "DEP";
  }

  if (/\b(?:TRF|TRANSFER|POINT\s*TO\s*POINT|CITY\s+TRANSFER)\b/.test(normalizedValue)) {
    return "TRF";
  }

  if (/\b(?:MNG|ARRIVAL|ARRIVING|MEET\s*(?:AND|&)\s*GREET|AIRPORT\s+PICK)\b/.test(normalizedValue)) {
    return "MNG";
  }

  return normalizedValue.replace(/[^A-Z0-9]+/g, " ").trim();
}

function serviceChangePriceReviewServiceLabel(value: string | null | undefined) {
  const rawValue = clean(value);
  const canonicalServiceType = canonicalServiceTypeForPriceReview(rawValue);
  const standardLabel =
    canonicalServiceType === "MNG" ||
    canonicalServiceType === "DEP" ||
    canonicalServiceType === "TRF" ||
    canonicalServiceType === "DSP"
      ? rateLabels[canonicalServiceType]
      : "";

  if (!rawValue) {
    return standardLabel || "Service to confirm";
  }

  if (!standardLabel) {
    return rawValue;
  }

  return rawValue.toUpperCase() === canonicalServiceType ? standardLabel : `${standardLabel} (${rawValue})`;
}

function buildServiceChangePriceReview(
  bookingValue: BookingForm,
  appliedRecord: AdminBookingPersistenceRecord | null | undefined,
  reviewedCustomerPrice: number,
): ServiceChangePriceReview | null {
  if (!appliedRecord) {
    return null;
  }

  const bookingReference = clean(appliedRecord.booking_reference);
  const oldServiceRaw = adminBookingPersistenceServiceType(appliedRecord);
  const newServiceRaw = clean(bookingValue.bookingType);
  const oldServiceType = canonicalServiceTypeForPriceReview(oldServiceRaw);
  const newServiceType = canonicalServiceTypeForPriceReview(newServiceRaw);

  if (!bookingReference || !oldServiceType || !newServiceType || oldServiceType === newServiceType) {
    return null;
  }

  const customerAccount =
    normalizeCompanyAccount(bookingValue.company, bookingValue.bookerEmail) ||
    adminBookingPersistenceCustomerDisplayName(appliedRecord) ||
    clean(bookingValue.booker) ||
    "Customer/account to confirm";
  const travelerName =
    clean(bookingValue.name) ||
    clean(appliedRecord.passenger_name) ||
    "Passenger/traveler to confirm";
  const reviewedAmountLabel = `$${formatCompactMoney(reviewedCustomerPrice)}`;
  const key = [
    bookingReference,
    oldServiceType,
    clean(oldServiceRaw).toUpperCase(),
    newServiceType,
    clean(newServiceRaw).toUpperCase(),
    normalizeBillingIdentityMatch(customerAccount),
    normalizeBillingIdentityMatch(travelerName),
    reviewedAmountLabel,
    clean(bookingValue.customerPriceOverride),
    clean(bookingValue.customerPriceOverrideReason),
    clean(bookingValue.manualExtraCharges),
    clean(bookingValue.manualExtraChargesNote),
  ].join("::");

  return {
    bookingReference,
    customerAccount,
    key,
    newServiceLabel: serviceChangePriceReviewServiceLabel(newServiceRaw),
    newServiceType,
    oldServiceLabel: serviceChangePriceReviewServiceLabel(oldServiceRaw),
    oldServiceType,
    reviewedAmountLabel,
    travelerName,
  };
}

const mockCustomerDomainMatches = new Map([
  ["marriott.com", "ritz-carlton"],
  ["ritzcarlton.com", "ritz-carlton"],
  ["ritzcarlton.com.sg", "ritz-carlton"],
  ["ubs.com", "ubs"],
  ["ubs.com.sg", "ubs"],
]);

function findMockCustomerById(customerId: string | null | undefined) {
  return mockCustomers.find((customer) => customer.id === customerId) ?? null;
}

function findMockCustomerByText(value: string | null | undefined, onlyIndividual = false) {
  const query = normalizeCompactSearch(value);

  if (!query) {
    return null;
  }

  return (
    mockCustomers.find((customer) => {
      if (onlyIndividual && clean(customer.accountType).toLowerCase() !== "individual") {
        return false;
      }

      const searchableValues = [
        customer.companyName,
        customer.id,
        customer.invoicePrefix,
      ].map(normalizeCompactSearch);

      return searchableValues.some(
        (candidate) => candidate && (candidate === query || candidate.includes(query) || query.includes(candidate)),
      );
    }) ?? null
  );
}

function deriveAdminMonthlyInvoicePrefix(customerAccount: string | null | undefined) {
  const cleanedAccount = clean(customerAccount);
  const configuredPrefix = clean(findMockCustomerByText(cleanedAccount)?.invoicePrefix).toUpperCase();

  if (/^[A-Z0-9]{2,12}$/.test(configuredPrefix)) {
    return configuredPrefix;
  }

  const compactAccount = cleanedAccount.toUpperCase().replace(/[^A-Z0-9]/g, "");

  if (compactAccount.length >= 2) {
    return compactAccount.slice(0, 12);
  }

  return "INV";
}

function findMockCustomerByEmailDomain(domain: string | null | undefined) {
  const emailDomain = normaliseEmailDomain(domain);
  const mappedCustomer = findMockCustomerById(mockCustomerDomainMatches.get(emailDomain));

  if (mappedCustomer) {
    return mappedCustomer;
  }

  return findMockCustomerByText(emailDomain.replace(/\.[a-z]{2,}$/i, ""));
}

function getMockCustomerMatchSuggestion(bookingValue: BookingForm): MockCustomerMatchSuggestion {
  const safeCompany = normalizeCompanyAccount(bookingValue.company, bookingValue.bookerEmail);
  const email = normaliseEmail(bookingValue.bookerEmail);
  const rawEmailDomain = normaliseEmailDomain(email.split("@")[1]);
  const organizationEmailDomain = getEmailDomain(email);
  const hasPublicEmail = Boolean(rawEmailDomain && isPublicEmailDomain(rawEmailDomain));
  const personName = clean(bookingValue.name) || clean(bookingValue.booker);
  const contactValue = clean(bookingValue.bookerEmail) || clean(bookingValue.bookerContact);
  const companyMatch = findMockCustomerByText(safeCompany);

  if (organizationEmailDomain) {
    const domainMatch = findMockCustomerByEmailDomain(organizationEmailDomain);

    if (domainMatch) {
      return {
        confidence: "High",
        customerId: domainMatch.id,
        customerName: domainMatch.companyName,
        isExistingCustomer: true,
        matchReason: `Organization email domain ${organizationEmailDomain} matches an existing mock customer folder.`,
        suggestedAction: "Link to existing customer",
      };
    }
  }

  if (companyMatch) {
    return {
      confidence: "High",
      customerId: companyMatch.id,
      customerName: companyMatch.companyName,
      isExistingCustomer: true,
      matchReason: `Company/account "${safeCompany}" matches an existing mock customer folder.`,
      suggestedAction: "Link to existing customer",
    };
  }

  if (organizationEmailDomain) {
    return {
      confidence: "Medium",
      customerId: null,
      customerName: "New customer suggested",
      isExistingCustomer: false,
      matchReason: `Organization email domain ${organizationEmailDomain} does not match a current mock customer.`,
      suggestedAction: "Create new customer folder",
    };
  }

  if (hasPublicEmail) {
    const individualMatch =
      findMockCustomerByText(personName, true) ||
      findMockCustomerByText(contactValue, true);

    if (individualMatch) {
      return {
        confidence: "Medium",
        customerId: individualMatch.id,
        customerName: individualMatch.companyName,
        isExistingCustomer: true,
        matchReason: `Public/personal email domain ${rawEmailDomain} is not used to create a company account; matched by individual name/email only.`,
        suggestedAction: "Update existing customer contact",
      };
    }

    return {
      confidence: "Needs review",
      customerId: null,
      customerName: "New customer suggested",
      isExistingCustomer: false,
      matchReason: `Public/personal email domain ${rawEmailDomain} is not used to create or suggest a company account.`,
      suggestedAction: "Create new customer folder",
    };
  }

  const individualNameMatch = findMockCustomerByText(personName, true);

  if (individualNameMatch) {
    return {
      confidence: "Medium",
      customerId: individualNameMatch.id,
      customerName: individualNameMatch.companyName,
      isExistingCustomer: true,
      matchReason: "Passenger/booker name matches an existing individual mock customer folder.",
      suggestedAction: "Update existing customer contact",
    };
  }

  return {
    confidence: "Needs review",
    customerId: null,
    customerName: "New customer suggested",
    isExistingCustomer: false,
    matchReason: "No existing mock customer matched the parsed company, domain, name, email, or contact.",
    suggestedAction: "Create new customer folder",
  };
}

function isValidEmail(value: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(normaliseEmail(value));
}

function normalizePhone(value: string) {
  return clean(value).replace(/[^\d+]/g, "");
}

function normalizeCompactSearch(value: string | null | undefined) {
  return clean(value).toLowerCase().replace(/[^a-z0-9]/g, "");
}

function driverSearchValuesMatch(
  values: Array<string | null | undefined>,
  query: string,
) {
  const search = clean(query).toLowerCase();
  const compactSearch = normalizeCompactSearch(search);
  const phoneSearch = /[a-z]/i.test(search) ? "" : normalizePhone(search);

  if (!search) {
    return false;
  }

  return values.some((value) => {
    const searchableValue = clean(value).toLowerCase();

    return (
      searchableValue.includes(search) ||
      Boolean(phoneSearch && normalizePhone(searchableValue).includes(phoneSearch)) ||
      Boolean(compactSearch && normalizeCompactSearch(searchableValue).includes(compactSearch))
    );
  });
}

function driverDisplayMatchesSearch(driver: DriverAssignmentDisplayRecord, query: string) {
  return driverSearchValuesMatch(
    [
      driver.driver_name,
      driver.contact_number,
      driver.plate_number,
      driver.vehicle_type,
      driver.availability_status,
    ],
    query,
  );
}

function isRatesSetupErrorMessage(value: string) {
  const text = clean(value).toLowerCase();

  return (
    (text.includes("schema cache") &&
      (text.includes("rate_settings") ||
        text.includes("customer_rates") ||
        text.includes("driver_payout_rules"))) ||
    text.includes("relation \"public.rate_settings\" does not exist") ||
    text.includes("relation \"rate_settings\" does not exist") ||
    text.includes("column \"customer_rates\" does not exist") ||
    text.includes("column \"driver_payout_rules\" does not exist") ||
    text.includes("column \"midnight_surcharge\" does not exist") ||
    text.includes("column \"extra_stop_surcharge\" does not exist") ||
    text.includes("column \"midnight_payout\" does not exist") ||
    text.includes("column \"extra_stop_payout\" does not exist") ||
    text.includes("column \"child_seat_customer_surcharge\" does not exist") ||
    text.includes("column \"child_seat_driver_payout\" does not exist")
  );
}

function formatRatesSetupError(value: string, fallbackPrefix: string) {
  return isRatesSetupErrorMessage(value)
    ? `${fallbackPrefix}Rates database not set up. Run Supabase migration.`
    : `${fallbackPrefix}${value}`;
}

function formatSupabaseError(error: unknown) {
  if (!error || typeof error !== "object") {
    return error instanceof Error ? error.message : "Unknown Supabase error.";
  }

  const details = error as {
    message?: string;
    details?: string;
    hint?: string;
    code?: string;
  };

  return [
    details.message,
    details.details ? `Details: ${details.details}` : "",
    details.hint ? `Hint: ${details.hint}` : "",
    details.code ? `Code: ${details.code}` : "",
  ].filter(Boolean).join(" ");
}

function compactParsedBooking(parsedBooking: ParsedBooking | null | undefined) {
  return Object.fromEntries(
    Object.entries(parsedBooking ?? {}).filter(([key, value]) =>
      key === "success" ? typeof value === "boolean" : key === "time" ? value !== undefined : hasParsedValue(value),
    ),
  ) as ParsedBooking;
}

function parseBookingMessageForState(messageText: string): ParsedBooking {
  return compactParsedBooking(parseJobCardBookingMessage(messageText));
}

function mergeParsedBookingIntoForm(
  currentBooking: BookingForm,
  parsedBooking: ParsedBooking,
): BookingForm {
  const parsedName = clean(parsedBooking.name);
  const parsedExtraStopLocation = clean(parsedBooking.extraStopLocation);
  const parsedExtraStopCount = parsedExtraStopLocation ? clean(parsedBooking.extraStopCount) || "1" : parsedBooking.extraStopCount;
  const bookingFields = Object.fromEntries(
    Object.entries(parsedBooking).filter(
      ([key]) => !["success", "cleanedLines", "extractedBookingsPreview", "parserWarning", "multipleBookingsDetected", "standbyUntil", "returnDestination"].includes(key),
    ),
  ) as Partial<BookingForm>;
  const mergedBooking = mergeParsedBookingState(currentBooking, {
    ...bookingFields,
    ...(parsedName ? { name: parsedName } : {}),
    ...(parsedExtraStopCount ? { extraStopCount: parsedExtraStopCount } : {}),
  });
  const safeCompany = normalizeCompanyAccount(
    mergedBooking.company,
    clean(mergedBooking.bookerEmail) || clean(currentBooking.bookerEmail),
  );

  return {
    ...currentBooking,
    ...mergedBooking,
    company: safeCompany,
    booker:
      clean(mergedBooking.booker) ||
      clean(currentBooking.booker) ||
      (!safeCompany && parsedName && clean(mergedBooking.bookingType).toUpperCase() !== "DSP"
        ? parsedName
        : ""),
    name: parsedName,
  };
}

function mergeCrmUpdatesIntoForm(
  currentBooking: BookingForm,
  crmUpdates: ParsedBooking,
): BookingForm {
  const currentName = clean(currentBooking.name);
  const crmName = clean(crmUpdates.name);
  const bookingFields = Object.fromEntries(
    Object.entries(crmUpdates).filter(
      ([key]) => !["success", "cleanedLines", "extractedBookingsPreview", "parserWarning", "multipleBookingsDetected", "standbyUntil", "returnDestination"].includes(key),
    ),
  ) as Partial<BookingForm>;
  const mergedBooking = mergeParsedBookingState(currentBooking, {
    ...bookingFields,
    name: currentName || crmName,
  });
  const safeCompany = normalizeCompanyAccount(
    mergedBooking.company,
    clean(mergedBooking.bookerEmail) || clean(currentBooking.bookerEmail),
  );

  return {
    ...currentBooking,
    ...mergedBooking,
    company: safeCompany,
    name: currentName || crmName,
  };
}

function formatDate(value: string) {
  if (!value) {
    return "Date TBC";
  }

  const date = new Date(`${value}T00:00:00`);
  if (Number.isNaN(date.getTime())) {
    return value;
  }

  return new Intl.DateTimeFormat("en-SG", {
    day: "2-digit",
    month: "short",
    year: "numeric",
  }).format(date);
}

function formatMoney(value: string | number | null | undefined) {
  return numericRate(value).toFixed(2);
}

function formatCompactMoney(value: string | number | null | undefined) {
  const formattedValue = formatMoney(value);

  return formattedValue.endsWith(".00") ? formattedValue.slice(0, -3) : formattedValue;
}

function getPricingReviewWarnings(pricing: { customerPrice: number; driverPayout: number; profit: number }) {
  if (pricing.profit >= 0) {
    return [];
  }

  return [
    `Negative profit: customer $${formatCompactMoney(pricing.customerPrice)} is below driver payout $${formatCompactMoney(pricing.driverPayout)}`,
  ];
}

function finiteNumber(value: unknown) {
  if (
    value === null ||
    value === undefined ||
    typeof value === "boolean" ||
    (typeof value === "string" && !clean(value))
  ) {
    return null;
  }

  const parsedValue = typeof value === "number" ? value : Number(value);

  return Number.isFinite(parsedValue) ? parsedValue : null;
}

function bookingCardPriceAmounts(bookingRecord: BookingRecord) {
  const childSeatCount = normalizeChildSeatCount(
    Boolean(bookingRecord.child_seat_required) || Boolean(finiteNumber(bookingRecord.child_seat_count)),
    bookingRecord.child_seat_count,
  );
  const extraStopCount = normalizeExtraStopCount(bookingRecord.extra_stop_count);
  const customerBasePrice = finiteNumber(bookingRecord.customer_rate);
  const driverBasePayout = finiteNumber(bookingRecord.driver_payout_min);
  const customerPrice =
    finiteNumber(bookingRecord.customer_price_amount) ??
    finiteNumber(bookingRecord.customer_rate_override) ??
    (customerBasePrice === null
      ? null
      : customerBasePrice +
        (finiteNumber(bookingRecord.midnight_surcharge) ?? 0) +
        extraStopCount * (finiteNumber(bookingRecord.extra_stop_surcharge) ?? 0) +
        (finiteNumber(bookingRecord.child_seat_customer_surcharge) ??
          childSeatCount * defaultChildSeatCustomerSurcharge));
  const driverPrice =
    finiteNumber(bookingRecord.driver_payout_override) ??
    (driverBasePayout === null
      ? null
      : driverBasePayout +
        (finiteNumber(bookingRecord.midnight_payout) ?? 0) +
        extraStopCount * (finiteNumber(bookingRecord.extra_stop_payout) ?? 0) +
        (finiteNumber(bookingRecord.child_seat_driver_payout) ?? childSeatCount * defaultChildSeatDriverPayout)) ??
    finiteNumber(bookingRecord.driver_payout_amount);

  return {
    customerPrice,
    driverPrice,
  };
}

// Kept parked for the separate finance/payout lane; loaded booking operational cards no longer call it.
// eslint-disable-next-line @typescript-eslint/no-unused-vars
function bookingCardPriceLine(bookingRecord: BookingRecord) {
  const { customerPrice, driverPrice } = bookingCardPriceAmounts(bookingRecord);

  if (customerPrice === null && driverPrice === null) {
    return "";
  }

  const customerText = customerPrice === null ? "—" : `$${formatCompactMoney(customerPrice)}`;
  const driverText = driverPrice === null ? "—" : `$${formatCompactMoney(driverPrice)}`;

  return `Customer ${customerText} / Driver ${driverText}`;
}

function positiveRateOrDefault(value: unknown, fallback: number) {
  const numericValue = finiteNumber(value);

  return numericValue !== null && numericValue > 0 ? numericValue : fallback;
}

function normalizeCustomerRateRules(rules: RateRules | null | undefined) {
  const source = (rules ?? {}) as Record<string, unknown>;
  const normalizedRules: RateRules = {};

  for (const bookingType of rateBookingTypes) {
    const numericValue = finiteNumber(source[bookingType]);

    if (numericValue !== null) {
      normalizedRules[bookingType] = numericValue;
    }
  }

  return normalizedRules;
}

function normalizeDriverPayoutRules(rules: DriverPayoutRules | null | undefined) {
  const source = (rules ?? {}) as Record<string, DriverPayoutRule | number | string | null | undefined>;
  const normalizedRules: DriverPayoutRules = {};

  for (const bookingType of rateBookingTypes) {
    const rule = source[bookingType];

    if (rule === null || rule === undefined) {
      continue;
    }

    if (typeof rule !== "object") {
      const amount = finiteNumber(rule);

      if (amount !== null) {
        normalizedRules[bookingType] =
          bookingType === "DSP" ? { amount, perHour: true } : { min: amount, max: amount };
      }

      continue;
    }

    const amount = finiteNumber(rule.amount);
    const min = finiteNumber(rule.min);
    const max = finiteNumber(rule.max);
    const normalizedRule: DriverPayoutRule = {};

    if (amount !== null) {
      normalizedRule.amount = amount;
    }

    if (min !== null) {
      normalizedRule.min = min;
    }

    if (max !== null) {
      normalizedRule.max = max;
    }

    if (rule.perHour !== undefined) {
      normalizedRule.perHour = Boolean(rule.perHour);
    }

    if (Object.keys(normalizedRule).length > 0) {
      normalizedRules[bookingType] = normalizedRule;
    }
  }

  return normalizedRules;
}

function getNonPositiveRateOverrideLabels(
  customerRates: RateRules | null | undefined,
  driverPayoutRules: DriverPayoutRules | null | undefined,
) {
  const invalidLabels: string[] = [];
  const customerSource = (customerRates ?? {}) as Record<string, unknown>;
  const driverSource = (driverPayoutRules ?? {}) as Record<string, DriverPayoutRule | number | string | null | undefined>;

  for (const bookingType of rateBookingTypes) {
    if (Object.prototype.hasOwnProperty.call(customerSource, bookingType)) {
      const numericValue = finiteNumber(customerSource[bookingType]);

      if (numericValue === null || numericValue <= 0) {
        invalidLabels.push(`${bookingType} customer`);
      }
    }

    if (!Object.prototype.hasOwnProperty.call(driverSource, bookingType)) {
      continue;
    }

    const payoutRule = driverSource[bookingType];

    if (payoutRule === null || payoutRule === undefined) {
      continue;
    }

    if (typeof payoutRule !== "object") {
      const amount = finiteNumber(payoutRule);

      if (amount === null || amount <= 0) {
        invalidLabels.push(`${bookingType} driver`);
      }

      continue;
    }

    const payoutValues = [payoutRule.amount, payoutRule.min, payoutRule.max]
      .map((value) => finiteNumber(value))
      .filter((value): value is number => value !== null);

    if (payoutValues.length === 0 || payoutValues.some((value) => value <= 0)) {
      invalidLabels.push(`${bookingType} driver`);
    }
  }

  return invalidLabels;
}

function formatOverrideSummary(
  customerRates: RateRules | null | undefined,
  driverPayoutRules: DriverPayoutRules | null | undefined,
) {
  const normalizedCustomerRates = normalizeCustomerRateRules(customerRates);
  const normalizedDriverPayoutRules = normalizeDriverPayoutRules(driverPayoutRules);
  const customerLabels = rateBookingTypes
    .filter((bookingType) => normalizedCustomerRates[bookingType] !== undefined)
    .map((bookingType) => `${bookingType} ${formatMoney(normalizedCustomerRates[bookingType])}`);
  const driverLabels = rateBookingTypes
    .filter((bookingType) => normalizedDriverPayoutRules[bookingType] !== undefined)
    .map((bookingType) => {
      const payoutRule = normalizedDriverPayoutRules[bookingType]!;

      return `${bookingType} ${formatMoney(payoutAmountFromRule(payoutRule))}`;
    });

  return {
    customerText: customerLabels.length > 0 ? `Customer: ${customerLabels.join(", ")}` : "Customer: None",
    driverText: driverLabels.length > 0 ? `Driver: ${driverLabels.join(", ")}` : "Driver: None",
    hasOverrides: customerLabels.length > 0 || driverLabels.length > 0,
  };
}

function hasRateOverrideValues(record: Pick<CompanyRecord, "customer_rates" | "driver_payout_rules">) {
  return formatOverrideSummary(record.customer_rates, record.driver_payout_rules).hasOverrides;
}

function hasCustomerRateOverrideValues(rules: RateRules) {
  return Object.keys(normalizeCustomerRateRules(rules)).length > 0;
}

function hasDriverPayoutOverrideValues(rules: DriverPayoutRules) {
  return Object.keys(normalizeDriverPayoutRules(rules)).length > 0;
}

type DefaultRateSettingsScalarRuntimePayload = {
  child_seat_customer_surcharge: number;
  child_seat_driver_payout: number;
  extra_stop_payout: number;
  extra_stop_surcharge: number;
  id: "default";
  midnight_payout: number;
  midnight_surcharge: number;
};

type DefaultRateSettingsLegacyRateMapsPayload = {
  customer_rates: Required<RateRules>;
  driver_payout_rules: Required<DriverPayoutRules>;
};

type DefaultRateSettingsLegacyScalarFallbackPayload = {
  child_seat_customer_surcharge?: number;
  child_seat_driver_payout?: number;
  extra_stop_payout?: number;
  extra_stop_surcharge?: number;
  id: "default";
  midnight_payout?: number;
  midnight_surcharge?: number;
};

type RateSettingsRuntimeWriteResponse = {
  error?: string;
  no_op?: boolean;
  ok?: boolean;
  reason?: string;
  rejected_fields?: unknown;
  status?: string;
};

function buildDefaultRateSettingsScalarPayload(
  settings: RateSettings,
): DefaultRateSettingsScalarRuntimePayload {
  return {
    child_seat_customer_surcharge: settings.childSeatCustomerSurcharge,
    child_seat_driver_payout: settings.childSeatDriverPayout,
    extra_stop_payout: settings.extraStopPayout,
    extra_stop_surcharge: settings.extraStopSurcharge,
    id: "default",
    midnight_payout: settings.midnightPayout,
    midnight_surcharge: settings.midnightSurcharge,
  };
}

function buildDefaultRateSettingsLegacyRateMapsPayload(
  settings: RateSettings,
): DefaultRateSettingsLegacyRateMapsPayload {
  return {
    customer_rates: {
      ...defaultCustomerRates,
      ...normalizeCustomerRateRules(settings.customerRates),
    },
    driver_payout_rules: {
      ...defaultDriverPayoutRules,
      ...normalizeDriverPayoutRules(settings.driverPayoutRules),
    },
  };
}

function buildDefaultRateSettingsLegacyScalarFallbackPayload(
  settings: DefaultRateSettingsScalarRuntimePayload,
  typedScalarSaved: boolean,
): DefaultRateSettingsLegacyScalarFallbackPayload {
  if (typedScalarSaved) {
    return {
      id: settings.id,
    };
  }

  return {
    child_seat_customer_surcharge: settings.child_seat_customer_surcharge,
    child_seat_driver_payout: settings.child_seat_driver_payout,
    extra_stop_payout: settings.extra_stop_payout,
    extra_stop_surcharge: settings.extra_stop_surcharge,
    id: settings.id,
    midnight_payout: settings.midnight_payout,
    midnight_surcharge: settings.midnight_surcharge,
  };
}

function rateSettingsRuntimeRejectedFields(value: RateSettingsRuntimeWriteResponse | null) {
  return Array.isArray(value?.rejected_fields)
    ? value.rejected_fields.map((field) => clean(field)).filter(Boolean)
    : [];
}

function rateSettingsRuntimeWriteSaved(value: RateSettingsRuntimeWriteResponse | null) {
  return value?.ok === true && clean(value.status).toLowerCase() === "saved";
}

function isRateSettingsRuntimeWriteBlockedNoOp(value: RateSettingsRuntimeWriteResponse | null) {
  const reason = clean(value?.reason).toLowerCase();

  return (
    value?.ok !== true &&
    value?.no_op === true &&
    ["admin_session_required", "config_not_ready", "write_gate_closed"].includes(reason)
  );
}

function rateSettingsRuntimeWriteError(
  value: RateSettingsRuntimeWriteResponse | null,
  fallback: string,
) {
  const rejectedFields = rateSettingsRuntimeRejectedFields(value);

  if (rejectedFields.length > 0) {
    return `${fallback} Rejected fields: ${rejectedFields.join(", ")}.`;
  }

  return clean(value?.error) || fallback;
}

async function saveDefaultRateSettingsScalarRuntime(
  payload: DefaultRateSettingsScalarRuntimePayload,
): Promise<{ ok: true; saved: boolean } | { errorMessage: string; ok: false }> {
  try {
    const response = await fetch(adminRateSettingsRuntimeWriteActionApiPath, {
      body: JSON.stringify(payload),
      headers: {
        "content-type": "application/json",
        "x-prestige-admin-purpose": adminLegacyDataPurpose,
      },
      method: "POST",
    });
    const responseBody = (await response.json().catch(() => null)) as RateSettingsRuntimeWriteResponse | null;

    if (response.ok && responseBody?.ok === true) {
      return { ok: true, saved: rateSettingsRuntimeWriteSaved(responseBody) };
    }

    if (isRateSettingsRuntimeWriteBlockedNoOp(responseBody)) {
      return { ok: true, saved: false };
    }

    return {
      ok: false,
      errorMessage: rateSettingsRuntimeWriteError(
        responseBody,
        "Default rate scalar save was rejected by the typed boundary.",
      ),
    };
  } catch (error) {
    return {
      ok: false,
      errorMessage: error instanceof Error
        ? error.message
        : "Default rate scalar save could not continue to the guarded legacy map fallback.",
    };
  }
}

