async function reserveAdminMonthlyInvoiceNumberForIssueRecord(
  issueRecord: AdminMonthlyInvoiceIssueRecordRecord,
) {
  const issueRecordId = clean(issueRecord.id);
  const customerAccount = clean(issueRecord.customer_account);
  const billingMonth = clean(issueRecord.billing_month);
  const invoicePrefix = deriveAdminMonthlyInvoicePrefix(customerAccount);

  if (!issueRecordId || !customerAccount || !billingMonth) {
    throw new Error("Monthly invoice number reservation requires a saved issue record.");
  }

  if (issueRecord.invoice_number_status === "reserved" || clean(issueRecord.invoice_number)) {
    throw new Error("Monthly invoice number is already reserved for this saved issue record.");
  }

  const response = await fetch(adminMonthlyInvoiceNumberReservationsApiPath, {
    body: JSON.stringify({
      billing_month: billingMonth,
      customer_account: customerAccount,
      invoice_prefix: invoicePrefix,
      issue_record_id: issueRecordId,
      safe_sequence_note: "Reserved from admin monthly invoice issue record control.",
    }),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice number reservation failed.");
  }

  const reservation =
    result.invoice_number_reservation as AdminMonthlyInvoiceNumberReservationRecord | null;

  if (!reservation || clean(reservation.issue_record_id) !== issueRecordId) {
    throw new Error("Monthly invoice number reservation response was empty.");
  }

  const { issueRecords } = await loadAdminMonthlyInvoiceIssueRecordsRead({
    billingMonth,
    customerAccountSearch: customerAccount,
    draftId: clean(issueRecord.draft_id),
    issueRecordId,
    issueReviewId: clean(issueRecord.issue_review_id),
    limit: 1,
    page: 1,
  });
  const refreshedRecord =
    issueRecords.find((record) => clean(record.id) === issueRecordId) || null;

  if (
    !refreshedRecord ||
    refreshedRecord.invoice_number_status !== "reserved" ||
    clean(refreshedRecord.invoice_number) !== clean(reservation.invoice_number)
  ) {
    throw new Error("Monthly invoice number reservation load-back failed.");
  }

  return {
    refreshedRecord,
    reservation,
  };
}

async function markAdminMonthlyInvoiceIssueRecordPdfReviewReady(
  issueRecord: AdminMonthlyInvoiceIssueRecordRecord,
) {
  const issueRecordId = clean(issueRecord.id);

  if (!issueRecordId) {
    throw new Error("Monthly invoice PDF review readiness requires a saved issue record.");
  }

  const response = await fetch(adminMonthlyInvoiceIssueRecordPdfReadinessApiPath, {
    body: JSON.stringify({
      issue_record_id: issueRecordId,
      safe_issue_record_note:
        "Marked ready for separate PDF review from admin monthly invoice issue record control.",
    }),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice PDF review readiness failed.");
  }

  const readyIssueRecord = result.issue_record as AdminMonthlyInvoiceIssueRecordRecord | null;

  if (
    !readyIssueRecord ||
    clean(readyIssueRecord.id) !== issueRecordId ||
    readyIssueRecord.issue_record_status !== "pdf_generation_ready" ||
    readyIssueRecord.pdf_generation_status !== "ready_to_generate"
  ) {
    throw new Error("Monthly invoice PDF review readiness response was incomplete.");
  }

  return readyIssueRecord;
}

async function saveAdminMonthlyBillingDraftPlanFromGroup(group: AdminMonthlyBillingGroup) {
  const customerAccount = clean(group.customer_account);
  const billingMonth = clean(group.billing_month);
  const readyCount = adminMonthlyBillingGroupingCount(group.ready_count);
  const blockedCount = adminMonthlyBillingGroupingCount(group.blocked_count);
  const totalCount = adminMonthlyBillingGroupingCount(group.total_count);
  const readinessStatus = group.safe_readiness_status || "blocked";

  if (!customerAccount || !billingMonth || totalCount < 1) {
    throw new Error("Monthly billing draft plan requires a saved customer/month group.");
  }

  const draftStatus: AdminMonthlyBillingDraftPlanStatus =
    readinessStatus === "ready" && blockedCount === 0
      ? "ready_for_billing_draft_review"
      : blockedCount > 0
        ? "blocked"
        : "planning";
  const response = await fetch(adminMonthlyBillingDraftPlansApiPath, {
    body: JSON.stringify({
      billing_month: billingMonth,
      blocked_count: blockedCount,
      customer_account: customerAccount,
      customer_id: clean(group.customer_id) || null,
      draft_status: draftStatus,
      ready_count: readyCount,
      readiness_status: readinessStatus,
      safe_draft_context: {
        draft_summary: `${totalCount} saved completed trip${totalCount === 1 ? "" : "s"} grouped for monthly billing draft planning.`,
        next_action:
          draftStatus === "blocked"
            ? "Resolve blocked saved trips before invoice draft preparation."
            : "Review saved group counts before invoice draft preparation.",
      },
      safe_draft_note: "Saved from admin monthly billing grouping read.",
      source_grouping_summary: {
        billing_month: billingMonth,
        blocked_count: blockedCount,
        customer_account: customerAccount,
        readiness_status: readinessStatus,
        ready_count: readyCount,
        source: "admin_monthly_billing_grouping_read",
        total_count: totalCount,
      },
      total_count: totalCount,
    }),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly billing draft plan save failed.");
  }

  const draftPlan = result.draft_plan as AdminMonthlyBillingDraftPlanRecord | null;

  if (!draftPlan) {
    throw new Error("Monthly billing draft plan response was empty.");
  }

  return draftPlan;
}

async function loadAdminMonthlyInvoiceDraftTripCandidatesRead(group: AdminMonthlyBillingGroup) {
  const customerAccount = clean(group.customer_account);
  const billingMonth = clean(group.billing_month);

  if (!customerAccount || !billingMonth) {
    throw new Error("Monthly invoice draft trip candidate read requires a saved customer/month group.");
  }

  const params = new URLSearchParams({
    billing_month: billingMonth,
    customer_account: customerAccount,
    limit: "250",
    page: "1",
  });
  const customerId = clean(group.customer_id);

  if (customerId) {
    params.set("customer_id", customerId);
  }

  const response = await fetch(
    `${adminMonthlyInvoiceDraftTripCandidatesApiPath}?${params.toString()}`,
    {
      headers: {
        "x-prestige-admin-purpose": adminLegacyDataPurpose,
      },
      method: "GET",
    },
  );
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice draft trip candidate read failed.");
  }

  return Array.isArray(result.trip_candidates)
    ? (result.trip_candidates as AdminMonthlyInvoiceDraftTripCandidate[])
    : [];
}

async function saveAdminMonthlyInvoiceDraftPreparation({
  existingDraft,
  group,
}: {
  existingDraft: AdminMonthlyInvoiceDraftRecord | null;
  group: AdminMonthlyBillingGroup;
}) {
  const customerAccount = clean(group.customer_account);
  const billingMonth = clean(group.billing_month);
  const readyCount = adminMonthlyBillingGroupingCount(group.ready_count);
  const blockedCount = adminMonthlyBillingGroupingCount(group.blocked_count);
  const totalCount = adminMonthlyBillingGroupingCount(group.total_count);
  const readinessStatus = group.safe_readiness_status || "blocked";

  if (!customerAccount || !billingMonth || totalCount < 1) {
    throw new Error("Monthly invoice draft preparation requires a saved customer/month group.");
  }

  const safeDraftContext = {
    draft_summary: `${totalCount} saved completed trip${totalCount === 1 ? "" : "s"} grouped for monthly draft prep.`,
    next_action:
      blockedCount > 0
        ? "Review blocked saved trips before manager approval."
        : "Review saved group counts before manager approval.",
    review_status: existingDraft
      ? "Saved draft prep refreshed from grouped data."
      : "Saved draft prep created from grouped data.",
  };
  const sharedPayload = {
    billing_month: billingMonth,
    blocked_count: blockedCount,
    customer_account: customerAccount,
    draft_status: existingDraft?.draft_status || "pending_admin_review",
    ready_count: readyCount,
    readiness_status: readinessStatus,
    safe_draft_context: safeDraftContext,
    safe_draft_note: "Saved from admin monthly group read.",
    source_grouping_summary: {
      billing_month: billingMonth,
      blocked_count: blockedCount,
      customer_account: customerAccount,
      readiness_status: readinessStatus,
      ready_count: readyCount,
      source: "admin_monthly_billing_grouping_read",
      total_count: totalCount,
    },
    total_count: totalCount,
  };
  const linkedTrips = existingDraft?.id
    ? []
    : (await loadAdminMonthlyInvoiceDraftTripCandidatesRead(group)).map((candidate) => ({
        billing_prep_readiness: clean(candidate.billing_prep_readiness) || null,
        booking_reference: clean(candidate.booking_reference),
        closeout_id: clean(candidate.closeout_id) || null,
        closeout_status: clean(candidate.closeout_status) || null,
        safe_trip_context: candidate.safe_trip_context || {},
        trip_readiness_status:
          candidate.trip_readiness_status === "blocked" ? "blocked" : "ready",
      })).filter((candidate) => Boolean(candidate.booking_reference));

  if (!existingDraft?.id && linkedTrips.length === 0) {
    throw new Error("Monthly invoice draft preparation requires saved trip references.");
  }

  const request =
    existingDraft?.id
      ? {
          body: {
            ...sharedPayload,
            draft_id: existingDraft.id,
          },
          method: "PATCH",
        }
      : {
          body: {
            ...sharedPayload,
            customer_id: clean(group.customer_id) || null,
            linked_trips: linkedTrips,
          },
          method: "POST",
        };

  const response = await fetch(adminMonthlyInvoiceDraftsApiPath, {
    body: JSON.stringify(request.body),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: request.method,
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice draft preparation save failed.");
  }

  const invoiceDraft = result.invoice_draft as AdminMonthlyInvoiceDraftRecord | null;

  if (!invoiceDraft) {
    throw new Error("Monthly invoice draft preparation response was empty.");
  }

  return invoiceDraft;
}

async function saveAdminMonthlyInvoiceIssueReviewFromDraft({
  existingReview,
  invoiceDraft,
}: {
  existingReview: AdminMonthlyInvoiceIssueReviewRecord | null;
  invoiceDraft: AdminMonthlyInvoiceDraftRecord;
}) {
  const draftId = clean(invoiceDraft.id);
  const customerAccount = clean(invoiceDraft.customer_account);
  const billingMonth = clean(invoiceDraft.billing_month);
  const readyCount = adminMonthlyBillingGroupingCount(invoiceDraft.ready_count);
  const blockedCount = adminMonthlyBillingGroupingCount(invoiceDraft.blocked_count);
  const totalCount = adminMonthlyBillingGroupingCount(invoiceDraft.total_count);
  const readinessStatus: AdminMonthlyInvoiceIssueReviewReadinessStatus =
    invoiceDraft.readiness_status || "blocked";
  const draftStatusSnapshot: AdminMonthlyInvoiceDraftStatus =
    invoiceDraft.draft_status || "pending_admin_review";

  if (!draftId || !customerAccount || !billingMonth || totalCount < 1) {
    throw new Error("Monthly invoice issue review requires a saved invoice draft.");
  }

  if (totalCount !== readyCount + blockedCount) {
    throw new Error("Monthly invoice issue review requires matching saved draft counts.");
  }

  const issueReviewStatus: AdminMonthlyInvoiceIssueReviewStatus =
    existingReview?.issue_review_status ||
    (readinessStatus === "ready" && blockedCount === 0 && draftStatusSnapshot === "manager_approved"
      ? "ready_for_future_issue"
      : blockedCount > 0 || readinessStatus === "blocked"
        ? "blocked"
        : draftStatusSnapshot === "manager_approved" ||
            draftStatusSnapshot === "manager_approval_needed"
          ? "manager_review_required"
          : "issue_review_pending");
  const safeIssueContext = {
    issue_summary: `${totalCount} saved monthly invoice draft trip${totalCount === 1 ? "" : "s"} ready for issue-review checks.`,
    next_action:
      issueReviewStatus === "blocked"
        ? "Resolve blocked saved draft trips before future issue review."
        : "Review saved draft counts before future issue approval.",
    review_status: existingReview
      ? "Saved issue review refreshed from the existing invoice draft."
      : "Saved issue review created from the existing invoice draft.",
  };
  const sharedPayload = {
    billing_month: billingMonth,
    blocked_count: blockedCount,
    customer_account: customerAccount,
    draft_id: draftId,
    draft_status_snapshot: draftStatusSnapshot,
    issue_review_status: issueReviewStatus,
    ready_count: readyCount,
    readiness_status: readinessStatus,
    safe_issue_context: safeIssueContext,
    safe_issue_note: "Saved from admin monthly invoice draft preparation review.",
    source_draft_summary: {
      billing_month: billingMonth,
      blocked_count: blockedCount,
      customer_account: customerAccount,
      draft_id: draftId,
      draft_status: draftStatusSnapshot,
      readiness_status: readinessStatus,
      ready_count: readyCount,
      source: "admin_monthly_invoice_draft_read",
      total_count: totalCount,
    },
    total_count: totalCount,
  };
  const response = await fetch(adminMonthlyInvoiceIssueReviewsApiPath, {
    body: JSON.stringify(sharedPayload),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: existingReview ? "PATCH" : "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice issue review save failed.");
  }

  const issueReview = result.issue_review as AdminMonthlyInvoiceIssueReviewRecord | null;

  if (!issueReview) {
    throw new Error("Monthly invoice issue review response was empty.");
  }

  return issueReview;
}

async function saveAdminMonthlyInvoiceDraftItemReviewFromDraft({
  existingItemReview,
  invoiceDraft,
}: {
  existingItemReview: AdminMonthlyInvoiceDraftItemReviewRecord | null;
  invoiceDraft: AdminMonthlyInvoiceDraftRecord;
}) {
  const draftId = clean(invoiceDraft.id);
  const linkedTrips = Array.isArray(invoiceDraft.linked_trips)
    ? invoiceDraft.linked_trips
    : [];
  const firstTrip = linkedTrips.find((trip) => clean(trip.booking_reference)) || null;
  const bookingReference = clean(firstTrip?.booking_reference);
  const draftTripLinkId = clean(firstTrip?.id) || null;
  const tripReadinessStatus = firstTrip?.trip_readiness_status || "blocked";
  const closeoutStatus = clean(firstTrip?.closeout_status) || null;
  const billingPrepReadiness = clean(firstTrip?.billing_prep_readiness) || null;
  const tripReady =
    tripReadinessStatus === "ready" &&
    (closeoutStatus === "closed" || closeoutStatus === "ready_for_billing_prep") &&
    billingPrepReadiness === "ready";

  if (!draftId || !bookingReference) {
    throw new Error("Monthly invoice draft item review requires a saved invoice draft trip.");
  }

  const itemReviewStatus: AdminMonthlyInvoiceDraftItemReviewStatus = tripReady
    ? "reviewed"
    : "blocked";
  const tripDetailReviewStatus: AdminMonthlyInvoiceDraftTripDetailReviewStatus = tripReady
    ? "reviewed"
    : "blocked";
  const extraChargeReviewStatus: AdminMonthlyInvoiceDraftExtraChargeReviewStatus = tripReady
    ? "none"
    : "blocked";
  const billingItemDecision: AdminMonthlyInvoiceDraftBillingItemDecision = tripReady
    ? "include_in_draft"
    : "blocked";
  const response = await fetch(adminMonthlyInvoiceDraftItemReviewsApiPath, {
    body: JSON.stringify({
      billing_item_decision: billingItemDecision,
      booking_reference: bookingReference,
      draft_id: draftId,
      ...(draftTripLinkId ? { draft_trip_link_id: draftTripLinkId } : {}),
      extra_charge_review_status: extraChargeReviewStatus,
      ...(clean(existingItemReview?.id) ? { item_review_id: clean(existingItemReview?.id) } : {}),
      item_review_status: itemReviewStatus,
      safe_item_review_context: {
        item_review_summary: tripReady
          ? "Saved draft trip item reviewed for invoice draft preparation."
          : "Saved draft trip item blocked until trip details are corrected.",
        next_action: tripReady
          ? "Continue reviewing remaining draft items before issue review."
          : "Resolve the blocked saved draft trip before issue review.",
        review_status: existingItemReview
          ? "Saved item review refreshed from invoice draft trip link."
          : "Saved item review created from invoice draft trip link.",
      },
      safe_item_review_note: "Saved from admin monthly invoice draft trip review.",
      source_trip_summary: {
        billing_prep_readiness: billingPrepReadiness,
        booking_reference: bookingReference,
        closeout_status: closeoutStatus,
        source: "monthly_invoice_draft_trip_link",
        trip_readiness_status: tripReadinessStatus,
      },
      trip_detail_review_status: tripDetailReviewStatus,
    }),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: existingItemReview ? "PATCH" : "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice draft item review save failed.");
  }

  const itemReview = result.item_review as AdminMonthlyInvoiceDraftItemReviewRecord | null;

  if (!itemReview) {
    throw new Error("Monthly invoice draft item review response was empty.");
  }

  return itemReview;
}

async function saveAdminMonthlyInvoiceBillablePriceReviewFromItemReview({
  bookingTypeHint,
  dspActualTimeSummary,
  existingPriceReview,
  invoiceDraft,
  itemReview,
  reviewedAmountCents,
}: {
  bookingTypeHint: string | null;
  dspActualTimeSummary: AdminDriverJobDspActualTimeSummaryRecord | null;
  existingPriceReview: AdminMonthlyInvoiceBillableItemPriceReviewRecord | null;
  invoiceDraft: AdminMonthlyInvoiceDraftRecord;
  itemReview: AdminMonthlyInvoiceDraftItemReviewRecord;
  reviewedAmountCents: number;
}) {
  const draftId = clean(invoiceDraft.id);
  const itemReviewId = clean(itemReview.id);
  const bookingReference = clean(itemReview.booking_reference);
  const linkedTrips = Array.isArray(invoiceDraft.linked_trips)
    ? invoiceDraft.linked_trips
    : [];
  const linkedTrip =
    linkedTrips.find((trip) => clean(trip.id) === clean(itemReview.draft_trip_link_id)) ||
    linkedTrips.find((trip) => clean(trip.booking_reference) === bookingReference) ||
    null;
  const draftTripLinkId = clean(itemReview.draft_trip_link_id) || clean(linkedTrip?.id) || null;
  const itemSummary = itemReview.source_trip_summary || {};
  const tripContext = linkedTrip?.safe_trip_context || {};
  const bookingType =
    adminMonthlyInvoiceBillableBookingTypeFromHint(bookingTypeHint) ||
    adminMonthlyInvoiceBillableBookingTypeFromHint(
      adminMonthlyInvoiceContextText(itemSummary, "booking_type"),
    ) ||
    adminMonthlyInvoiceBillableBookingTypeFromHint(
      adminMonthlyInvoiceContextText(tripContext, "booking_type"),
    );

  if (!draftId || !itemReviewId || !bookingReference || !bookingType) {
    throw new Error("Monthly invoice billable item price review requires a saved draft item and booking type.");
  }

  const calculationBasis = adminMonthlyInvoiceBillableCalculationBasis(bookingType);
  const dspTotalMinutes =
    adminMonthlyInvoiceContextNumber(itemSummary, "dsp_total_minutes") ??
    adminMonthlyInvoiceContextNumber(tripContext, "dsp_total_minutes") ??
    adminMonthlyInvoiceContextNumber(
      dspActualTimeSummary as Record<string, unknown> | null,
      "dsp_total_minutes",
    );
  const savedDspBillableMinutes =
    adminMonthlyInvoiceContextNumber(itemSummary, "dsp_billable_minutes") ??
    adminMonthlyInvoiceContextNumber(tripContext, "dsp_billable_minutes") ??
    adminMonthlyInvoiceContextNumber(
      dspActualTimeSummary as Record<string, unknown> | null,
      "dsp_billable_minutes",
    );
  const dspBillableMinutes = adminMonthlyInvoiceActualTimeBillableMinutes(
    bookingType,
    dspTotalMinutes,
    savedDspBillableMinutes,
  );
  const isDspBillableReview = calculationBasis === "dsp_actual_time";
  const hasDspActualMinutes =
    !isDspBillableReview || (dspTotalMinutes !== null && dspBillableMinutes !== null);
  const dspActualTimeStatus = clean(dspActualTimeSummary?.actual_time_status);
  const priceReviewStatus: AdminMonthlyInvoicePriceReviewStatus = hasDspActualMinutes
    ? "approved_for_invoice_draft"
    : "needs_correction";
  const priceDecision: AdminMonthlyInvoicePriceDecision = hasDspActualMinutes
    ? "include_in_invoice"
    : "needs_manager_review";
  const response = await fetch(adminMonthlyInvoiceBillableItemPriceReviewsApiPath, {
    body: JSON.stringify({
      billing_item_type: "base_trip",
      booking_reference: bookingReference,
      booking_type: bookingType,
      calculation_basis: calculationBasis,
      currency: "SGD",
      draft_id: draftId,
      ...(draftTripLinkId ? { draft_trip_link_id: draftTripLinkId } : {}),
      ...(isDspBillableReview && dspBillableMinutes !== null
        ? { dsp_billable_minutes: dspBillableMinutes }
        : {}),
      ...(isDspBillableReview && dspTotalMinutes !== null ? { dsp_total_minutes: dspTotalMinutes } : {}),
      item_review_id: itemReviewId,
      ...(clean(existingPriceReview?.id) ? { price_review_id: clean(existingPriceReview?.id) } : {}),
      price_decision: priceDecision,
      price_review_status: priceReviewStatus,
      reviewed_customer_amount_cents: reviewedAmountCents,
      safe_price_review_context: {
        ...(bookingType === "hourly" && dspTotalMinutes !== null && dspBillableMinutes !== null
          ? {
              hourly_billing_grace_minutes: hourlyBillingGraceMinutes,
              hourly_billing_rule: hourlyBillingGraceRuleText,
            }
          : {}),
        next_action: hasDspActualMinutes
          ? "Continue monthly invoice issue review after admin price approval."
          : "Save actual start/end minutes before approving this item for invoice draft.",
        price_review_summary: hasDspActualMinutes
          ? "Admin reviewed billable item amount for invoice draft preparation."
          : "Admin entered billable amount but actual start/end minutes are still needed.",
        review_status: existingPriceReview
          ? "Saved billable item price review refreshed from the existing item review."
          : "Saved billable item price review created from the existing item review.",
      },
      safe_price_review_note: "Saved from admin monthly invoice billable item price review.",
      source_price_context: {
        billing_item_type: "base_trip",
        booking_reference: bookingReference,
        booking_type: bookingType,
        calculation_basis: calculationBasis,
        ...(isDspBillableReview && dspActualTimeStatus
          ? { dsp_actual_time_status: dspActualTimeStatus }
          : {}),
        ...(isDspBillableReview && dspBillableMinutes !== null
          ? { dsp_billable_minutes: dspBillableMinutes }
          : {}),
        ...(isDspBillableReview && dspTotalMinutes !== null
          ? { dsp_total_minutes: dspTotalMinutes }
          : {}),
        ...(bookingType === "hourly" && dspTotalMinutes !== null && dspBillableMinutes !== null
          ? {
              hourly_billing_grace_minutes: hourlyBillingGraceMinutes,
              hourly_billing_rule: hourlyBillingGraceRuleText,
            }
          : {}),
        draft_id: draftId,
        item_review_status: itemReview.item_review_status || null,
        reviewed_amount_cents: reviewedAmountCents,
        source: "admin_monthly_invoice_draft_item_review",
      },
    }),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: existingPriceReview ? "PATCH" : "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice billable item price review save failed.");
  }

  const priceReview =
    result.price_review as AdminMonthlyInvoiceBillableItemPriceReviewRecord | null;

  if (!priceReview) {
    throw new Error("Monthly invoice billable item price review response was empty.");
  }

  return priceReview;
}

async function saveAdminMonthlyInvoiceIssueRecordFromReview({
  existingRecord,
  issueReview,
}: {
  existingRecord: AdminMonthlyInvoiceIssueRecordRecord | null;
  issueReview: AdminMonthlyInvoiceIssueReviewRecord;
}) {
  const issueReviewId = clean(issueReview.id);
  const draftId = clean(issueReview.draft_id);
  const customerAccount = clean(issueReview.customer_account);
  const billingMonth = clean(issueReview.billing_month);
  const readyCount = adminMonthlyBillingGroupingCount(issueReview.ready_count);
  const blockedCount = adminMonthlyBillingGroupingCount(issueReview.blocked_count);
  const totalCount = adminMonthlyBillingGroupingCount(issueReview.total_count);
  const readinessStatus: AdminMonthlyInvoiceIssueReviewReadinessStatus =
    issueReview.readiness_status || "blocked";
  const issueReviewStatus: AdminMonthlyInvoiceIssueReviewStatus =
    issueReview.issue_review_status || "issue_review_pending";

  if (!issueReviewId || !draftId || !customerAccount || !billingMonth || totalCount < 1) {
    throw new Error("Monthly invoice issue record requires a saved issue review.");
  }

  if (totalCount !== readyCount + blockedCount) {
    throw new Error("Monthly invoice issue record requires matching saved issue review counts.");
  }

  const issueReadyForLock =
    issueReviewStatus === "ready_for_future_issue" &&
    readinessStatus === "ready" &&
    blockedCount === 0;
  const initialIssueRecordStatus: AdminMonthlyInvoiceIssueRecordStatus = issueReadyForLock
    ? "draft_locked"
    : "blocked";
  const initialDraftLockStatus: AdminMonthlyInvoiceDraftLockStatus = issueReadyForLock
    ? "locked_for_issue"
    : "lock_blocked";
  const existingInvoiceNumber = clean(existingRecord?.invoice_number) || null;
  const existingIssueRecordStatus = existingRecord?.issue_record_status || null;
  const existingIssueStatusRequiresNumber = [
    "invoice_number_reserved",
    "pdf_generation_ready",
    "pdf_generated_not_sent",
    "sent_manually",
    "unpaid",
    "paid",
  ].includes(existingIssueRecordStatus || "");
  const issueRecordStatus: AdminMonthlyInvoiceIssueRecordStatus =
    existingIssueRecordStatus && (!existingIssueStatusRequiresNumber || existingInvoiceNumber)
      ? existingIssueRecordStatus
      : initialIssueRecordStatus;
  const draftLockStatus: AdminMonthlyInvoiceDraftLockStatus =
    existingRecord?.draft_lock_status || initialDraftLockStatus;
  const invoiceNumberStatus: AdminMonthlyInvoiceNumberStatus = existingInvoiceNumber
    ? "reserved"
    : existingRecord?.invoice_number_status === "reserved"
      ? "not_reserved"
      : existingRecord?.invoice_number_status || "not_reserved";
  const invoiceDeliveryStatus: AdminMonthlyInvoiceDeliveryStatus =
    existingRecord?.invoice_delivery_status || "not_sent";
  const rawPaymentRecordStatus: AdminMonthlyInvoicePaymentRecordStatus =
    existingRecord?.payment_record_status || "not_recorded";
  const paymentRecordStatus: AdminMonthlyInvoicePaymentRecordStatus =
    ["unpaid", "paid"].includes(rawPaymentRecordStatus) &&
    invoiceDeliveryStatus !== "sent_manually"
      ? "not_recorded"
      : rawPaymentRecordStatus;
  const pdfGenerationStatus: AdminMonthlyInvoicePdfGenerationStatus =
    existingRecord?.pdf_generation_status || "not_requested";
  const safeIssueRecordContext = {
    delivery_status: invoiceDeliveryStatus,
    invoice_number_status: invoiceNumberStatus,
    issue_summary: `${totalCount} saved monthly invoice issue-review trip${
      totalCount === 1 ? "" : "s"
    } checked for draft lock readiness.`,
    lock_status: draftLockStatus,
    next_action:
      issueRecordStatus === "blocked"
        ? "Resolve blocked saved issue-review items before draft lock completion."
        : "Keep the locked draft ready for separately approved invoice issue steps.",
    payment_record_status: paymentRecordStatus,
    pdf_generation_status: pdfGenerationStatus,
  };
  const sharedPayload = {
    billing_month: billingMonth,
    customer_account: customerAccount,
    draft_id: draftId,
    draft_lock_status: draftLockStatus,
    invoice_delivery_status: invoiceDeliveryStatus,
    invoice_number: existingInvoiceNumber,
    invoice_number_status: invoiceNumberStatus,
    issue_record_status: issueRecordStatus,
    issue_review_id: issueReviewId,
    payment_record_status: paymentRecordStatus,
    pdf_generation_status: pdfGenerationStatus,
    safe_issue_record_context: safeIssueRecordContext,
    safe_issue_record_note: "Saved from admin monthly invoice issue review.",
    source_issue_review_summary: {
      billing_month: billingMonth,
      blocked_count: blockedCount,
      customer_account: customerAccount,
      draft_id: draftId,
      issue_review_id: issueReviewId,
      issue_review_status: issueReviewStatus,
      readiness_status: readinessStatus,
      ready_count: readyCount,
      source: "admin_monthly_invoice_issue_review",
      total_count: totalCount,
    },
  };
  const issueRecordId = clean(existingRecord?.id);
  const response = await fetch(adminMonthlyInvoiceIssueRecordsApiPath, {
    body: JSON.stringify(
      issueRecordId
        ? {
            ...sharedPayload,
            issue_record_id: issueRecordId,
          }
        : sharedPayload,
    ),
    headers: {
      "Content-Type": "application/json",
      "x-prestige-admin-purpose": adminLegacyDataPurpose,
    },
    method: issueRecordId ? "PATCH" : "POST",
  });
  const result = await response.json().catch(() => null);

  if (!response.ok || !result?.ok) {
    throw new Error(result?.error || "Monthly invoice issue record save failed.");
  }

  const issueRecord = result.issue_record as AdminMonthlyInvoiceIssueRecordRecord | null;

  if (!issueRecord) {
    throw new Error("Monthly invoice issue record response was empty.");
  }

  return issueRecord;
}

function completedTripCloseoutReviewStatusFromApi(
  closeout: AdminCompletedBookingCloseoutRecord | null,
): CompletedTripCloseoutReviewStatus {
  if (!closeout) {
    return "review-needed";
  }

  const closeoutStatus = clean(closeout.closeout_status);
  const completedJobStatus = clean(closeout.completed_job_status);
  const billingPrepReadiness = clean(closeout.billing_prep_readiness);
  const closeoutSummary = clean(closeout.safe_closeout_context?.closeout_summary).toLowerCase();
  const closeoutNote = clean(closeout.safe_closeout_note).toLowerCase();
  const closeoutDispositionText = `${closeoutSummary} ${closeoutNote}`;

  if (completedJobStatus === "completion_exception") {
    if (/no[-\s]?show/.test(closeoutDispositionText)) {
      return "customer-no-show-billable";
    }

    if (/late\s+cancellation|late\s+cancel/.test(closeoutDispositionText)) {
      return "late-cancellation-billable";
    }

    if (/waiv|no\s+charge/.test(closeoutDispositionText) || billingPrepReadiness === "blocked") {
      return "waived-no-charge";
    }

    return "exception-reviewed";
  }

  if (closeoutStatus === "ready_for_billing_prep" || closeoutStatus === "closed") {
    return "ready-locally";
  }

  if (completedJobStatus === "completed") {
    return "trip-completed";
  }

  return "review-needed";
}

