  function applyDriverToBooking(driverId: string) {
    if (!driverId) {
      setBooking((current) => ({
        ...current,
        driverId: "",
        driverName: "",
        driverContact: "",
        driverPlate: "",
        driverVehicleModel: "",
        driverNotes: "",
      }));
      return;
    }

    const selectedDriver = driverAssignmentDisplayDrivers.find((driver) => String(driver.id) === driverId);

    if (!selectedDriver) {
      setBooking((current) => ({
        ...current,
        driverId,
      }));
      return;
    }

    setBooking((current) => ({
      ...current,
      driverId,
      driverName: clean(selectedDriver.driver_name),
      driverContact: clean(selectedDriver.contact_number),
      driverPlate: clean(selectedDriver.plate_number),
      driverVehicleModel: clean(selectedDriver.vehicle_type),
    }));
  }

