  async function saveCompletedTripCloseoutReviewStatus(
    nextStatus: CompletedTripCloseoutReviewStatus,
  ) {
    const bookingReference = clean(dispatchReleaseWorkflowBookingReference);

    setCompletedTripCloseoutReviewStatus(nextStatus);

    if (!bookingReference) {
      setCompletedTripCloseoutReviewMessage({
        tone: "error",
        text: "Load a saved booking or apply an operational snapshot before saving completed closeout.",
      });
      return;
    }

    const selectedLabel =
      completedTripCloseoutReviewOptions.find((option) => option.value === nextStatus)?.label ||
      "Completed closeout";
    const isBillableCloseoutException =
      nextStatus === "customer-no-show-billable" ||
      nextStatus === "late-cancellation-billable";
    const isNoChargeCloseoutException = nextStatus === "waived-no-charge";
    const closeoutStatus =
      nextStatus === "ready-locally" || isBillableCloseoutException
        ? "ready_for_billing_prep"
        : isNoChargeCloseoutException
          ? "closed"
          : "needs_review";
    const completedJobStatus =
      isBillableCloseoutException || isNoChargeCloseoutException
        ? "completion_exception"
        : nextStatus === "review-needed"
          ? "needs_review"
          : "completed";
    const dspActualHoursReadiness =
      isBillableCloseoutException || isNoChargeCloseoutException
        ? "not_applicable"
        : nextStatus === "ready-locally" || nextStatus === "billing-note-reviewed"
          ? "ready"
          : "needs_review";
    const extraChargesReadiness =
      nextStatus === "ready-locally" || isBillableCloseoutException
        ? "ready"
        : isNoChargeCloseoutException
          ? "none"
          : "needs_review";
    const billingPrepReadiness =
      nextStatus === "ready-locally" || isBillableCloseoutException
        ? "ready"
        : isNoChargeCloseoutException
          ? "blocked"
          : "not_ready";
    const closeoutSummary =
      nextStatus === "customer-no-show-billable"
        ? "Customer no-show billing review approved from the existing Completed Trip Closeout Review control."
        : nextStatus === "late-cancellation-billable"
          ? "Late cancellation billing review approved from the existing Completed Trip Closeout Review control."
          : nextStatus === "waived-no-charge"
            ? "Waived no-charge closeout approved from the existing Completed Trip Closeout Review control."
            : `${selectedLabel} from the existing Completed Trip Closeout Review control.`;
    const closeoutNextAction =
      nextStatus === "ready-locally" || isBillableCloseoutException
        ? "Continue customer billing preparation review after closeout."
        : isNoChargeCloseoutException
          ? "Keep the no-charge closeout archived away from active billing preparation."
          : "Continue completed trip closeout review before billing preparation.";
    const fallbackCloseoutNote =
      nextStatus === "customer-no-show-billable"
        ? "Admin marked customer no-show as billable after closeout review."
        : nextStatus === "late-cancellation-billable"
          ? "Admin marked late cancellation as billable after closeout review."
          : nextStatus === "waived-no-charge"
            ? "Admin marked closeout waived with no charge after review."
            : "Admin updated completed closeout from the existing closeout review control.";

    setCompletedBookingCloseoutAction("save-completed-closeout");
    setCompletedTripCloseoutReviewMessage({
      tone: "info",
      text: `Saving completed closeout for ${bookingReference}...`,
    });

    try {
      const response = await fetch(adminCompletedBookingCloseoutApiPath, {
        body: JSON.stringify({
          billing_prep_readiness: billingPrepReadiness,
          booking_reference: bookingReference,
          closeout_status: closeoutStatus,
          completed_job_status: completedJobStatus,
          dsp_actual_hours_readiness: dspActualHoursReadiness,
          extra_charges_readiness: extraChargesReadiness,
          safe_closeout_context: {
            closeout_summary: closeoutSummary,
            next_action: closeoutNextAction,
          },
          safe_closeout_note:
            clean(completedTripCloseoutReviewNote) ||
            fallbackCloseoutNote,
        }),
        headers: {
          "Content-Type": "application/json",
          "x-prestige-admin-purpose": adminLegacyDataPurpose,
        },
        method: "POST",
      });
      const result = await response.json().catch(() => null);

      if (!response.ok || !result?.ok) {
        throw new Error(result?.error || "Completed closeout save failed.");
      }

      const savedCloseout = result.closeout as AdminCompletedBookingCloseoutRecord;
      setCompletedBookingCloseoutRecord(savedCloseout);
      setCompletedTripCloseoutReviewStatus(
        completedTripCloseoutReviewStatusFromApi(savedCloseout),
      );
      setCompletedTripCloseoutReviewMessage({
        tone: "success",
        text: `Completed closeout saved for ${bookingReference}: ${adminCompletedBookingCloseoutDisplayLabel(
          savedCloseout,
        )}.`,
      });
    } catch (error) {
      setCompletedTripCloseoutReviewMessage({
        tone: "error",
        text: adminCompletedBookingCloseoutFailureMessage(error),
      });
    } finally {
      setCompletedBookingCloseoutAction(null);
    }
  }

  async function updateAppliedAdminBookingOperationalSnapshot() {
    const targetBookingReference = clean(appliedAdminBookingSnapshotReference);

    if (!targetBookingReference) {
      setAdminBookingPersistenceMessage({
        tone: "info",
        text: "Apply a loaded operational snapshot before updating.",
      });
      return;
    }

    const billingIdentityResolution = await resolveSaveCrmBillingIdentityAccountForSave();

    if (!billingIdentityResolution.ok) {
      setAdminBookingPersistenceMessage(billingIdentityResolution.message);
      return;
    }

    const serviceChangePriceReviewResolution = resolveServiceChangePriceReviewForSave();

    if (!serviceChangePriceReviewResolution.ok) {
      setAdminBookingPersistenceMessage(serviceChangePriceReviewResolution.message);
      return;
    }

    const payload = buildAdminBookingPersistencePayload(
      booking,
      currentTimeMs,
      targetBookingReference,
      {
        customerDisplayNameOverride: billingIdentityResolution.accountLabel,
      },
    );
    const appliedSnapshot = appliedAdminBookingSnapshot;

    if (appliedSnapshot) {
      payload.booking.source_channel = clean(appliedSnapshot.source_channel) || payload.booking.source_channel;
      payload.booking.customer_facing_status =
        clean(appliedSnapshot.customer_facing_status) || payload.booking.customer_facing_status;
      payload.booking.admin_internal_status =
        clean(appliedSnapshot.admin_internal_status) || payload.booking.admin_internal_status;
      payload.booking.short_notice_review_status =
        clean(appliedSnapshot.short_notice_review_status) || payload.booking.short_notice_review_status;
      payload.booking.request_review_status =
        clean(appliedSnapshot.request_review_status) || payload.booking.request_review_status;
    }

    setAdminBookingPersistenceAction("update");
    setAdminBookingPersistenceMessage({
      tone: "info",
      text: "Updating applied operational booking fields...",
    });

    try {
      const response = await fetch("/api/admin-bookings", {
        body: JSON.stringify({
          target_booking_reference: targetBookingReference,
          ...payload,
        }),
        headers: {
          "Content-Type": "application/json",
          "x-prestige-admin-purpose": "admin-booking-persistence",
        },
        method: "PATCH",
      });
      const result = await response.json();

      if (!response.ok || !result?.ok) {
        throw new Error(adminBookingPersistenceFailureDetail(result, "Admin booking update failed."));
      }

      const updatedBooking = result.booking as AdminBookingPersistenceRecord;
      const updatedBookingReference = clean(updatedBooking.booking_reference) || targetBookingReference;
      markAdminBookingAsActiveForUpdates(updatedBookingReference, updatedBooking);
      setAdminBookingPersistenceMessage({
        tone: "info",
        text: `Operational booking updated: ${updatedBookingReference}${
          updatedBooking.short_notice_review_status === "Admin Review Required"
            ? ". Admin Review Required."
            : "."
        } Syncing Google Calendar...`,
      });
      const calendarSyncResult = await autoSyncSavedBookingGoogleCalendar(updatedBooking);

      const updateMessage = {
        tone: calendarSyncResult.ok ? "success" : "error",
        text: calendarSyncResult.ok
          ? `Operational booking updated: ${updatedBookingReference}. Google Calendar auto-synced; reminders included; no guest email sent.`
          : `Operational booking updated: ${updatedBookingReference}. ${calendarSyncResult.message}`,
      } satisfies Message;

      setAdminBookingPersistenceMessage(updateMessage);
      setMessage(updateMessage);
      setBookingSaveMessage(updateMessage);
      if (calendarSyncResult.ok) {
        lastSuccessfulBookingSaveRef.current = {
          bookingId: updatedBookingReference,
          key: getBookingSaveGuardKey(updatedBookingReference),
          record: updatedBooking,
        };
      }
    } catch (error) {
      setAdminBookingPersistenceMessage({
        tone: "error",
        text: adminBookingPersistenceFailureMessage("update", error),
      });
    } finally {
      setAdminBookingPersistenceAction(null);
    }
  }

  async function updateAdminCustomerRequestReviewDecision(
    record: AdminBookingPersistenceRecord,
    decisionKey: AdminCustomerRequestReviewDecisionKey,
  ) {
    const decision = adminCustomerRequestReviewDecisions.find((candidate) => candidate.key === decisionKey);
    const targetBookingReference = clean(record.booking_reference);

    if (!decision || !targetBookingReference || !adminBookingPersistenceRecordIsCustomerRequest(record)) {
      setAdminBookingPersistenceMessage({
        tone: "error",
        text: "Customer request review decision could not be saved: loaded request details need review.",
      });
      return;
    }

    const payload = buildAdminCustomerRequestDecisionPayload(record, decision, currentTimeMs);

    if (!payload) {
      setAdminBookingPersistenceMessage({
        tone: "error",
        text: "Customer request review decision could not be saved: required operational details are missing.",
      });
      return;
    }

    const statuses = adminCustomerRequestDecisionStatuses(record, decision, currentTimeMs);

    setAdminBookingPersistenceAction("update");
    setAdminBookingPersistenceMessage({
      tone: "info",
      text: "Saving internal customer request review decision...",
    });

    try {
      const response = await fetch("/api/admin-bookings", {
        body: JSON.stringify({
          target_booking_reference: targetBookingReference,
          ...payload,
        }),
        headers: {
          "Content-Type": "application/json",
          "x-prestige-admin-purpose": "admin-booking-persistence",
        },
        method: "PATCH",
      });
      const result = await response.json();

      if (!response.ok || !result?.ok) {
        throw new Error(adminBookingPersistenceFailureDetail(result, "Admin review decision update failed."));
      }

      const updatedBooking = result.booking as AdminBookingPersistenceRecord;
      const customerNotificationResult = result.customer_notification as
        | { ok?: boolean; error?: string }
        | null
        | undefined;
      const updatedBookingReference = clean(updatedBooking.booking_reference) || targetBookingReference;
      setAdminBookingPersistenceRecords((current) => [
        updatedBooking,
        ...current.filter(
          (currentRecord) => clean(currentRecord.booking_reference) !== updatedBookingReference,
        ),
      ]);

      if (clean(appliedAdminBookingSnapshotReference) === targetBookingReference) {
        setAppliedAdminBookingSnapshotReference(updatedBookingReference);
      }

      setAdminBookingPersistenceMessage({
        tone: "success",
        text: `Internal review decision saved for ${updatedBookingReference}: ${decision.successLabel}.${
          customerNotificationResult?.ok
            ? " Customer in-app notification queued."
            : customerNotificationResult
              ? " Customer in-app notification could not be queued."
              : " Customer notification not queued for this update."
        }${
          statuses.shortNoticeReviewRequired
            ? " Short-notice review was handled by this decision."
            : ""
        }`,
      });
    } catch (error) {
      setAdminBookingPersistenceMessage({
        tone: "error",
        text: adminBookingPersistenceFailureMessage("update", error),
      });
    } finally {
      setAdminBookingPersistenceAction(null);
    }
  }

  function getDispatchCopyText(target: DispatchCopyTarget) {
    const copyEditState = copyEditStates[target];
    const generatedText = generatedDispatchCopyMessages[target];

    return copyEditState.sourceKey === dispatchCopyResetKey &&
      copyEditState.generatedText === generatedText &&
      copyEditState.editedText !== null
      ? copyEditState.editedText
      : generatedText;
  }

  function getRenderableCopyEditState(target: DispatchCopyTarget) {
    const copyEditState = copyEditStates[target];

    return copyEditState.sourceKey === dispatchCopyResetKey &&
      copyEditState.generatedText === generatedDispatchCopyMessages[target]
      ? copyEditState
      : {
          ...copyEditState,
          draftText: "",
          editedText: null,
          isEditing: false,
        };
  }

  function updateCopyEditDraft(target: DispatchCopyTarget, value: string) {
    setCopyEditStates((current) => ({
      ...current,
      [target]: {
        ...current[target],
        draftText: value,
      },
    }));
  }

  function startCopyEdit(target: DispatchCopyTarget) {
    setCopyEditStates((current) => ({
      ...current,
      [target]: {
        ...current[target],
        draftText:
          current[target].sourceKey === dispatchCopyResetKey &&
          current[target].generatedText === generatedDispatchCopyMessages[target] &&
          current[target].editedText !== null
            ? current[target].editedText
            : generatedDispatchCopyMessages[target],
        generatedText: generatedDispatchCopyMessages[target],
        isEditing: true,
        sourceKey: dispatchCopyResetKey,
      },
    }));
    setCopyFeedback({
      target,
      tone: "info",
      text: `${dispatchCopyLabels[target]} ready to edit.`,
    });
  }

  function saveCopyEdit(target: DispatchCopyTarget) {
    setCopyEditStates((current) => ({
      ...current,
      [target]: {
        ...current[target],
        editedText: current[target].draftText,
        isEditing: false,
      },
    }));
    setCopyFeedback({
      target,
      tone: "success",
      text: `${dispatchCopyLabels[target]} edit saved.`,
    });
  }

  function cancelCopyEdit(target: DispatchCopyTarget) {
    setCopyEditStates((current) => ({
      ...current,
      [target]: {
        draftText: "",
        editedText: null,
        generatedText: generatedDispatchCopyMessages[target],
        isEditing: false,
        sourceKey: dispatchCopyResetKey,
      },
    }));
    setCopyFeedback({
      target,
      tone: "info",
      text: `${dispatchCopyLabels[target]} edit cancelled. Generated text restored.`,
    });
  }

  async function copyDispatchCopy(target: DispatchCopyTarget) {
    try {
      await navigator.clipboard.writeText(getDispatchCopyText(target));
      setCopyFeedback({ target, tone: "success", text: `${dispatchCopyLabels[target]} copied.` });
    } catch {
      setCopyFeedback({
        target,
        tone: "error",
        text: `Copy failed. Select the ${dispatchCopyLabels[target].toLowerCase()} text manually.`,
      });
    }
  }

  async function copyJobCard() {
    await copyDispatchCopy("jobCard");
  }

  async function copyCustomerCopy() {
    await copyDispatchCopy("customerCopy");
  }

  function adminDriverJobLinkFailureMessage(error: unknown) {
    const errorText = error instanceof Error ? error.message : "Unknown driver job link error.";

    return `Driver job link request could not be completed: ${errorText}`;
  }

  function buildAdminDriverJobLinkCreatePayload() {
    const bookingReference = clean(dispatchReleaseWorkflowBookingReference);
    const driverName = clean(booking.driverName) || clean(assignedDriverRecord?.driver_name);
    const driverContact = clean(booking.driverContact) || clean(assignedDriverRecord?.contact_number);
    const driverPlate = assignedDriverPlate;
    const vehicleModel =
      clean(booking.driverVehicleModel) ||
      clean(assignedDriverRecord?.vehicle_type) ||
      clean(booking.vehicle);
    const pickupDateTime = formatPickupDateTime(booking.date, booking.time);
    const pickupLocation = clean(booking.pickup);
    const dropoffLocation = clean(booking.dropoff);
    const passengerName = clean(booking.name);

    if (!bookingReference) {
      return {
        error: "Load a saved booking before creating a driver job link.",
        ok: false as const,
      };
    }

    if (!pickupLocation || !dropoffLocation || !clean(booking.date) || !clean(booking.time)) {
      return {
        error: "Pickup, drop-off, pickup date, and pickup time are required before creating a driver job link.",
        ok: false as const,
      };
    }

    const driverJobPayload: {
      assigned_driver_contact?: string;
      assigned_driver_name?: string;
      assigned_driver_plate?: string;
      assigned_driver_vehicle_model?: string;
      booking_type: string;
      dropoff_location: string;
      flight_no: string;
      passenger_name: string;
      pickup_date: string;
      pickup_datetime: string;
      pickup_location: string;
      pickup_time: string;
      route: string;
      status: string;
      waypoints: string[];
    } = {
      assigned_driver_vehicle_model: vehicleModel || "Vehicle TBC",
      booking_type: clean(booking.bookingType),
      dropoff_location: dropoffLocation,
      flight_no: clean(booking.flight),
      passenger_name: passengerName,
      pickup_date: clean(booking.date),
      pickup_datetime: pickupDateTime,
      pickup_location: pickupLocation,
      pickup_time: formatPickupTime(booking.time),
      route: route,
      status: clean(dispatchReleaseAppliedStatus) || "assigned",
      waypoints: isDspItinerary
        ? itineraryDisplayStops.map((stop) => clean(stop.location)).filter(Boolean)
        : [],
    };

    if (driverName) {
      driverJobPayload.assigned_driver_name = driverName;
    }

    if (driverContact) {
      driverJobPayload.assigned_driver_contact = driverContact;
    }

    if (driverPlate) {
      driverJobPayload.assigned_driver_plate = driverPlate;
    }

    return {
      data: {
        booking_reference: bookingReference,
        driver_job_payload: driverJobPayload,
        ttl_hours: 48,
      },
      ok: true as const,
    };
  }

  async function createDriverJobLink() {
    const payloadResult = buildAdminDriverJobLinkCreatePayload();

    if (!payloadResult.ok) {
      setAdminDriverJobLinkState((current) => ({
        ...current,
        message: {
          tone: "error",
          text: payloadResult.error,
        },
      }));
      return;
    }

    setDriverJobLinkCopyMessage(null);
    setAdminDriverJobLinkState((current) => ({
      ...current,
      action: "create",
      message: {
        tone: "info",
        text: `Creating driver job link for ${payloadResult.data.booking_reference}...`,
      },
      oneTimeUrl: "",
    }));

    try {
      const response = await fetch(adminDriverJobLinksApiPath, {
        body: JSON.stringify(payloadResult.data),
        headers: {
          "Content-Type": "application/json",
          "x-prestige-admin-purpose": adminLegacyDataPurpose,
        },
        method: "POST",
      });
      const result = await response.json().catch(() => null);

      if (!response.ok || !result?.ok) {
        throw new Error(result?.error || "Driver job link create failed.");
      }

      const link = result.link as AdminDriverJobLinkRecord;
      const driverJobUrl = clean(result.driver_job_url);

      if (!link || !driverJobUrl) {
        throw new Error("Driver job link response was missing the one-time URL.");
      }

      setAdminDriverJobLinkState({
        action: null,
        link,
        loadedReference: link.booking_reference,
        message: {
          tone: "success",
          text: "Driver job link created. Copy the one-time link now; it will not be listed again.",
        },
        oneTimeUrl: driverJobUrl,
      });
    } catch (error) {
      setAdminDriverJobLinkState((current) => ({
        ...current,
        action: null,
        message: {
          tone: "error",
          text: adminDriverJobLinkFailureMessage(error),
        },
        oneTimeUrl: "",
      }));
    }
  }

  async function copyDriverJobLink() {
    if (!clean(adminDriverJobLinkState.oneTimeUrl)) {
      setAdminDriverJobLinkState((current) => ({
        ...current,
        message: {
          tone: "info",
          text: "Create a fresh driver job link before copying. Existing saved links cannot reveal the token again.",
        },
      }));
      return;
    }

    try {
      await navigator.clipboard.writeText(driverJobLinkMessage);
      setDriverJobLinkCopyMessage({ tone: "success", text: "Driver job link copied." });
    } catch {
      setDriverJobLinkCopyMessage({
        tone: "error",
        text: "Copy failed. Select the driver job link text manually.",
      });
    }
  }

  async function revokeDriverJobLink() {
    const driverJobLinkId = clean(activeAdminDriverJobLink?.id);

    if (!driverJobLinkId) {
      setAdminDriverJobLinkState((current) => ({
        ...current,
        message: {
          tone: "info",
          text: "No active driver job link is loaded to revoke.",
        },
      }));
      return;
    }

    setDriverJobLinkCopyMessage(null);
    setAdminDriverJobLinkState((current) => ({
      ...current,
      action: "revoke",
      message: {
        tone: "info",
        text: "Revoking driver job link...",
      },
    }));

    try {
      const response = await fetch(adminDriverJobLinksApiPath, {
        body: JSON.stringify({
          driver_job_link_id: driverJobLinkId,
        }),
        headers: {
          "Content-Type": "application/json",
          "x-prestige-admin-purpose": "admin-booking-persistence",
        },
        method: "PATCH",
      });
      const result = await response.json().catch(() => null);

      if (!response.ok || !result?.ok) {
        throw new Error(result?.error || "Driver job link revoke failed.");
      }

      setAdminDriverJobLinkState((current) => ({
        action: null,
        link: (result.link as AdminDriverJobLinkRecord) || current.link,
        loadedReference: current.loadedReference,
        message: {
          tone: "success",
          text: "Driver job link revoked.",
        },
        oneTimeUrl: "",
      }));
    } catch (error) {
      setAdminDriverJobLinkState((current) => ({
        ...current,
        action: null,
        message: {
          tone: "error",
          text: adminDriverJobLinkFailureMessage(error),
        },
      }));
    }
  }

