  function setBookingCompletionMessage(bookingId: string, nextMessage: Message | null) {
    setBookingCompletionMessages((current) => {
      if (!nextMessage) {
        const nextMessages = { ...current };
        delete nextMessages[bookingId];
        return nextMessages;
      } else {
        return { [bookingId]: nextMessage };
      }
    });
  }

  async function updateBookingStatusOnly(
    bookingRecord: BookingRecord,
    nextStatus: BookingStatusValue,
    loadingText: string,
    successText: string,
    errorPrefix: string,
  ) {
    const bookingId = String(bookingRecord.id);
    const bookingStatusReference =
      cleanReferenceText(bookingRecord.booking_reference) || bookingId;

    if (typeof fetch !== "function") {
      const errorMessage = {
        tone: "error",
        text: `${errorPrefix}: Admin saved booking status API is not available.`,
      } satisfies Message;
      setBookingCompletionMessage(bookingId, errorMessage);
      return;
    }

    const loadingMessage = { tone: "info", text: loadingText } satisfies Message;
    setCompletingBookingId(bookingId);
    setBookingCompletionMessage(bookingId, loadingMessage);

    try {
      const response = await fetch(adminSavedBookingStatusesApiPath, {
        body: JSON.stringify({
          booking_id: bookingStatusReference,
          status: nextStatus,
        }),
        headers: {
          "Content-Type": "application/json",
          "x-prestige-admin-purpose": "admin-booking-persistence",
        },
        method: "PATCH",
      });
      const responseBody = (await response.json().catch(() => null)) as AdminSavedBookingStatusResponse | null;

      if (
        !response.ok ||
        responseBody?.ok !== true ||
        !responseBody.booking ||
        String(responseBody.booking.id) !== bookingStatusReference ||
        responseBody.booking.status !== nextStatus ||
        !responseBody.booking.updated_at
      ) {
        const error = readAdminLegacyDataError(
          responseBody,
          "Admin saved booking status update request failed.",
        );

        throw new Error(formatSupabaseError(error));
      }

      setBookings((current) =>
        current.map((currentBooking) =>
          currentBooking.id === bookingRecord.id
            ? {
                ...currentBooking,
                status: nextStatus,
                updated_at: responseBody.booking?.updated_at || currentBooking.updated_at,
              }
            : currentBooking,
        ),
      );

      const successMessage = { tone: "success", text: successText } satisfies Message;
      setBookingCompletionMessage(bookingId, successMessage);
    } catch (error) {
      const errorText = error instanceof Error ? error.message : "Unknown booking status error.";
      const errorMessage = { tone: "error", text: `${errorPrefix}: ${errorText}` } satisfies Message;
      setBookingCompletionMessage(bookingId, errorMessage);
    } finally {
      setCompletingBookingId(null);
    }
  }

